window.ITEMS_UNIT7=[{"problem_id":"unit07-0001","original_source":"cpm-5-1","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Launches exponential growth using rabbit doubling; students represent repeated multiplication with description, diagram, and table.","question_html":"<section class=\"problem\" id=\"5-1\"><h2>5-1</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Launch exponential growth context; students represent rabbit growth with description, diagram, and table.</div><div><div class=\"row\"><div><p class=\"\" style=\"\">MULTIPLYING LIKE BUNNIES</p><p class=\"\" style=\"\">In the book <em>Of Mice and Men</em> by John Steinbeck, two good friends named Lennie and George dream of raising rabbits and living off the land.\u00a0 What if their dream came true?</p><p class=\"\" style=\"\">Suppose Lennie and George started with two rabbits and that in each month following those rabbits have two babies.\u00a0 Also suppose that every month thereafter, each pair of rabbits has two babies.</p></div><div style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div><p class=\"\" style=\"\"><strong>Your Task: </strong>With your team, determine how many rabbits Lennie and George would have after one year (<span class=\"math\">$12$</span> months).\u00a0 Represent this situation with a written description of the pattern of growth, a diagram, and a table.\u00a0 What patterns can you find and how do they compare to other patterns that you have investigated previously?\u00a0</p></div></section>"},{"problem_id":"unit07-0002","original_source":"cpm-5-2","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Develops the doubling/multiplicative growth pattern with diagrams and tables.","question_html":"<section class=\"problem\" id=\"5-2\"><h2>5-2</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Develops the doubling and multiplicative growth pattern with diagrams and tables.</div><div><p class=\"\" style=\"\"> How can you determine the number of rabbits that will exist at the end of one year?\u00a0 Consider this as you answer the questions below.  \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Draw a diagram to represent how the total number of rabbits is growing each month. How many rabbits will Lennie and George have after three months?</p></li><li><p class=\"\" style=\"\">As the number of rabbits becomes larger, a diagram becomes too cumbersome to be useful.\u00a0 A table might work better.\u00a0 Organize your information in a table showing the total number of rabbits for the first several months (at least <span class=\"math\">$6$</span> months).\u00a0 What patterns can you find in your table?\u00a0 Describe the pattern of growth in words. \u00a0</p></li><li><p class=\"\" style=\"\">If you have not done so already, use your pattern to determine the number of rabbits that Lennie and George would have after one year (<span class=\"math\">$12$</span> months) have passed.</p></li><li><p class=\"\" style=\"\">How does the growth in the table that you created compare to the growth patterns that you have investigated previously? \u00a0How is it similar and how is it different?</p></li></ol></div></section>"},{"problem_id":"unit07-0003","original_source":"cpm-5-3","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Compares exponential growth scenarios by varying starting amount and growth rate.","question_html":"<section class=\"problem\" id=\"5-3\"><h2>5-3</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Compares exponential growth scenarios by changing starting amount and growth rate.</div><div><p class=\"\" style=\"\"> Lennie and George want to raise as many rabbits as possible, so they have a few options to consider.\u00a0 They could start with a larger number of rabbits, or they could raise a breed of rabbits that reproduces faster.\u00a0 How do you think that each of these options would change the pattern of growth you observed in the previous problem?\u00a0 Which situation might yield the largest rabbit population after one year?  \t</p><ol class=\"lower-alpha\"><li><p class=\"\" style=\"\">To help answer these questions, model each case below with a table for the first five months.\u00a0<br/><br/> \t\tCase 2: Start with <span class=\"math\">$10$</span> rabbits; each pair has <span class=\"math\">$2$</span> babies per month.<br/><br/> \t\tCase 3: Start with <span class=\"math\">$2$</span> rabbits; each pair has <span class=\"math\">$4$</span> babies per month.<br/><br/> \t\tCase 4: Start with <span class=\"math\">$2$</span> rabbits; each pair has <span class=\"math\">$6$</span> babies per month.</p></li><li><p class=\"\" style=\"\">Which case would appear to give Lennie and George the most rabbits after one year? \u00a0How many rabbits would they have in that case? \u00a0</p></li></ol></div></section>"},{"problem_id":"unit07-0004","original_source":"cpm-5-5","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Learning Log","audit_status":"authoritative","notes":"Reflection on what distinguishes exponential functions from linear functions.","question_html":"<section class=\"problem\" id=\"5-5\"><h2>5-5</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Learning Log reflection on what makes exponential functions distinct from linear functions.</div><div><p class=\"\" style=\"\"> LEARNING LOG \t</p><p class=\"\" style=\"\">To represent the growth in number of rabbits in problems\u00a05-1 and 5-3, you discovered a new function family that is not linear.\u00a0 Functions in this new family are called exponential functions.\u00a0 Throughout this chapter and later in Chapter 7, you will learn more about this special family of functions.</p><div class=\"row\"><div><p class=\"\" style=\"\">Write a Learning Log entry to record what you have learned so far about exponential functions.\u00a0 For example, what do their graphs look like?\u00a0 What patterns do you observe in their tables?\u00a0 Title this entry \u201cExponential Functions\u201d and include today\u2019s date.</p></div><div style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div></div></section>"},{"problem_id":"unit07-0005","original_source":"cpm-5-6","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Completes exponential-growth tables using multiplicative patterns.","question_html":"<section class=\"problem\" id=\"5-6\"><h2>5-6</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Review/Preview completing exponential-growth tables using a multiplicative pattern.</div><div><p class=\"\" style=\"\">What if the data for Lennie and George (from problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-1</span>) matched the data in each table below? Assuming that the growth of the rabbits multiplies as it did in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-1</span>, complete each of the following tables. Show your thinking or give a brief explanation of how you know what the missing entries are.\u00a0\u00a0</p><div class=\"row\"><div><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th data-colwidth=\"60\" style=\"text-align:center;width:60px;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\">Months</p></th><th data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-bottom:1px solid black;\"><p class=\"\">Rabbits</p></th></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$0$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$4$</span></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$1$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$12$</span></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$2$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$36$</span></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$3$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;\"><p class=\"\"><span class=\"math\">$4$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;\"><p class=\"\"></p></td></tr></tbody></table><p class=\"\" style=\"\"></p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th data-colwidth=\"60\" style=\"text-align:center;width:60px;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\">Months</p></th><th data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-bottom:1px solid black;\"><p class=\"\">Rabbits</p></th></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$0$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$6$</span></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$1$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$2$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$24$</span></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\"><span class=\"math\">$3$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\"></p></td></tr><tr><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-top:1px solid black;border-right:1px solid black;\"><p class=\"\"><span class=\"math\">$4$</span></p></td><td data-colwidth=\"60\" style=\"text-align:center;width:60px;border-left:1px solid black;border-top:1px solid black;\"><p class=\"\"><span class=\"math\">$96$</span></p></td></tr></tbody></table></li></ol></div></div></div></section>"},{"problem_id":"unit07-0006","original_source":"cpm-5-12","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Identifies and represents exponential bacterial growth with table and graph.","question_html":"<section class=\"problem\" id=\"5-12\"><h2>5-12</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth and Decay</div><div class=\"audit\">Audit note: Identifies and represents exponential bacterial growth with table and graph.</div><div><p class=\"\" style=\"\">Jill is studying a strange bacterium. When she first looks at the bacteria, there are <span class=\"math\">$1000$</span> cells in her sample. The next day, there are <span class=\"math\">$2000$</span> cells. Intrigued, she comes back the next day to find that there are <span class=\"math\">$4000$</span> cells! \u00a0\u00a0 <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/iarz65fjwd\" rel=\"noopener\" target=\"_blank\">5-12 HW eTool</a></p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Should the graph of this situation be linear or curved?</p></li></ol><ul class=\"plain\"><li></li></ul><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\" style=\"\">Create a table and graph for this situation. The inputs are the days that have passed after she first began to study the sample, and the outputs are the numbers of cells of bacteria.</p></li></ol><ul class=\"plain\"><li></li></ul></div></section>","resources":[{"label":"5-12 HW eTool","href":"https://www.desmos.com/calculator/iarz65fjwd"}]},{"problem_id":"unit07-0007","original_source":"cpm-5-40","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Introduces geometric sequences as repeated multiplication in a rabbit-growth context.","question_html":"<section class=\"problem\" id=\"5-40\">\n<h2>5-40</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div><div class=\"audit\">Audit note: Introduces geometric sequences as repeated multiplication in the rabbit-growth context.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\"> Samantha was thinking about George and Lennie and their rabbits. When she listed the number of rabbits George and Lennie could have each month, she ended up with the ordered list below, called a<strong> sequence</strong>.  \t</p><p class=\"\">$2,6,18,54$, \u2026 </p><p class=\"\">\tShe realized that she could represent this situation using a sequence-generating machine that would generate the number of rabbits each month by doing something to the previous month\u2019s number of rabbits.\u00a0 She tested her generator by putting in a <strong>first term</strong>\u00a0of $2$ and she recorded each output before putting it into the next machine.\u00a0 Below is the diagram she used to explain her idea to her teammates.\u00a0  \t</p><p class=\"\"><img alt=\"Sequence generator diagram for 2, 6, 18, 54\" class=\"figure-img wide-figure\" src=\"assets/5-40.png\"/> </p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">What does Samantha's sequence generator seem to be doing to each input?</p></li><li><p class=\"\">What are the next two terms of Samantha's sequence? Show how you got your answer.</p></li><li><p class=\"\">Samantha decided to use the same sequence generator, but this time she started\u00a0with a first term of $5$. What are the next four terms in this new sequence?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0008","original_source":"cpm-5-43","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Names arithmetic and geometric sequences and distinguishes constant-add from constant-multiply patterns.","question_html":"<section class=\"problem\" id=\"5-43\">\n<h2>5-43</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div><div class=\"audit\">Audit note: Names arithmetic and geometric sequences and identifies constant-add versus constant-multiply patterns.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-sm-8\"><p class=\"\">Some types of sequences have special names. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">When the sequence generator <em>adds</em> a constant to each previous term, it is called an <span class=\"glossary-link\">arithmetic sequence</span>.\u00a0 Which of your sequences from problem\u00a05-41 fall into this family?\u00a0 Should you include the sequence labeled (f) in this family?\u00a0 Why or why not?</p></li><li><p class=\"\">When the sequence generator <em>multiplies</em> a constant times each previous term, it is called a <span class=\"glossary-link\">geometric sequence</span>.\u00a0 Which of the sequences from problem\u00a05-41 are geometric?\u00a0 Should sequence (h) be in this group?\u00a0 Why or why not?</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0009","original_source":"cpm-5-49","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Classifies bouncing-ball data and sequence behavior as exponential/geometric decay.","question_html":"<section class=\"problem\" id=\"5-49\">\n<h2>5-49</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div><div class=\"audit\">Audit note: Classifies bouncing-ball data and a sequence as exponential/geometric decay.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-sm-9\"><p class=\"\">Chelsea dropped a bouncy ball off the roof while Nery recorded its rebound height. The table at right shows their data. Note that the $0$ in the \u201cBounce\u201d column represents the starting height. </p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">To what family does the function belong? Explain how you know.</p></li><li><p class=\"\">Show the data as a sequence. Is the sequence arithmetic, geometric, quadratic, or something else? Justify your answer.</p></li></ol></div><div class=\"col-sm-3 col-align-top\"><table><tbody><tr><th><p class=\"\">Bounce</p></th><th><p class=\"\">Rebound<br/> Height</p></th></tr><tr><td><p class=\"\">$0$</p></td><td><p class=\"\">$800$ cm</p></td></tr><tr><td><p class=\"\">$1$</p></td><td><p class=\"\">$475$ cm</p></td></tr><tr><td><p class=\"\">$2$</p></td><td><p class=\"\">$290$ cm</p></td></tr><tr><td><p class=\"\">$3$</p></td><td><p class=\"\">$175$ cm</p></td></tr><tr><td><p class=\"\">$4$</p></td><td><p class=\"\">$100$ cm</p></td></tr><tr><td><p class=\"\">$5$</p></td><td><p class=\"\">$60$ cm</p></td></tr></tbody></table></div></div></div>\n</section>"},{"problem_id":"unit07-0010","original_source":"cpm-5-68","source_lesson":"Lesson 5.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Recognizes ticket prices increasing by a constant multiplier/percent-growth pattern.","question_html":"<section class=\"problem\" id=\"5-68\"><h2>5-68</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div><div class=\"audit\">Audit note: Recognizes ticket prices increasing by a constant multiplier or percent growth.</div>\n<div><p>Great Amusements Park has been raising its ticket prices every year, as shown in the table below \u00a0</p><table><tbody><tr><th><p>Year</p></th><th><p>Price</p></th></tr><tr><td><p>$0$</p></td><td><p>$\\$50$</p></td></tr><tr><td><p>$1$</p></td><td><p>$\\$55$</p></td></tr><tr><td><p>$2$</p></td><td><p>$\\$60.50$</p></td></tr><tr><td><p>$3$</p></td><td><p>$\\$66.55$</p></td></tr></tbody></table><ol class=\"lower-alpha\" type=\"a\"><li><p>Describe how the ticket prices are growing.</p></li><li><p>What will the price of admission be in year $6$?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0011","original_source":"cpm-5-85","source_lesson":"Lesson 5.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Classifies sequences as linear, exponential, or other and identifies add/multiply rates of change.","question_html":"<section class=\"problem\" id=\"5-85\">\n<h2>5-85</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div>\n<div class=\"audit\">Audit note: Classifies sequences as linear, exponential, or other and identifies add/multiply rates of change.</div>\n<div><p>Identify the following sequences as linear, exponential, or other. For the linear and exponential sequences, identify the rate of change and whether it is a constant that is added or multiplied. </p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p>\u00a0$12,144,1728,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>\u00a0$0,5,10,15,20,25,\\dots$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>\u00a0$0,4,16,36,64,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>\u00a0$1.5,2.25,3.375,5.0625,\\dots$\u00a0</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0012","original_source":"cpm-5-94","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Lesson","audit_status":"authoritative","notes":"Interprets multiplier/common ratio and connects multiplier size to growth or decay.","question_html":"<section class=\"problem\" id=\"5-94\">\n<h2>5-94</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div>\n<div class=\"audit\">Audit note: Interprets the multiplier/common ratio and connects multiplier size to growth or decay.</div>\n<div><p> In a geometric sequence, the sequence generator is the number that one term is multiplied by to generate the next term.  Another name for this number is the multiplier. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Look back at your work for problems 5-92 and 5-93.  What is the multiplier in each of these three situations?</p></li><li><p>What is the multiplier for the sequence $8, 8, 8, 8, \\ldots$?</p></li></ol><div class=\"row\"><div class=\"col-sm-9\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>Explain what happens to the terms of the sequence when the multiplier is less than 1, but greater than zero.  What happens when the multiplier is greater than 1?  Add this description to your Learning Log.  Title this entry \u201cMultipliers\u201d and add today\u2019s date.</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0013","original_source":"cpm-5-102","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Converts percent increases and decreases into multipliers; multiplier recognition.","question_html":"<section class=\"problem\" id=\"5-102\">\n<h2>5-102</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Converts percent increases and decreases into multipliers.</div>\n<div><p>Convert each percent increase or decrease into a multiplier. </p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p> $3\\%$ increase</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p> $25\\%$ decrease</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p> $13 \\%$ decrease</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p> $2.08\\%$ increase</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0014","original_source":"cpm-5-105","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Classifies graphed sequences as arithmetic, geometric, or neither and describes the generator.","question_html":"<section class=\"problem\" id=\"5-105\">\n<h2>5-105</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div>\n<div class=\"audit\">Audit note: Classifies graphed sequences as arithmetic, geometric, or neither and describes the generator.</div>\n<div><p>For this problem, refer to the sequences graphed below. </p><div class=\"row\"><div class=\"col-sm-4\"><p>#$1$ <img alt=\"Sequence graph #1\" class=\"figure-img\" src=\"assets/5-105-1.png\"/></p></div><div class=\"col-sm-4\"><p>#$2$  <img alt=\"Sequence graph #2\" class=\"figure-img\" src=\"assets/5-105-2.png\"/></p></div><div class=\"col-sm-4\"><p>#$3$ <img alt=\"Sequence graph #3\" class=\"figure-img\" src=\"assets/5-105-3.png\"/></p></div></div><ol class=\"lower-alpha\" type=\"a\"><li><p>Identify each sequence as arithmetic, geometric, or neither.</p></li><li><p>If it is arithmetic or geometric, describe the sequence generator.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0015","original_source":"cpm-CL5-124","source_lesson":"Chapter 5 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Closure","audit_status":"authoritative","notes":"Classifies sequences as arithmetic, geometric, or neither.","question_html":"<div class=\"card\">\n<div class=\"problem-title\">CL 5-124</div>\n<p>Determine if the following sequences are arithmetic, geometric, or neither:</p>\n<div class=\"grid-2\">\n<ol type=\"a\"><li>$-7,-3,1,5,9,\\ldots$</li></ol>\n<ol start=\"2\" type=\"a\"><li>$-64,-16,-4,-1,\\ldots$</li></ol>\n<ol start=\"3\" type=\"a\"><li>$1,0,1,4,9,\\ldots$</li></ol>\n<ol start=\"4\" type=\"a\"><li>$0,2,4,\\ldots$</li></ol>\n</div>\n</div>"},{"problem_id":"unit07-0016","original_source":"cpm-7-9","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Recognizes geometric decay and reasons about long-run behavior.","question_html":"<section class=\"problem\" id=\"7-9\">\n<h2>7-9</h2>\n<div class=\"meta\"><span class=\"pill\">Review/Preview</span><span>Sorted to Unit 7, Section 1</span></div>\n<div class=\"audit\">Audit note: Recognizes a geometric decay sequence, graphs it, and reasons about whether it reaches zero or negative values.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\">Consider the sequence that begins $40,20,10,5,\\dots$ </p><ol class=\"lower-alpha\"><li><p class=\"\" style=\"\">Based on the information given, can this sequence be arithmetic? Can it be geometric? Why?</p></li><li><p class=\"\" style=\"\">Assume this is a geometric sequence. On graph paper, plot the sequence on a graph up to $n=6$.</p></li><li><p class=\"\" style=\"\">Will the values of the sequence ever become zero or negative? Explain.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0017","original_source":"cpm-7-16","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Identifies multipliers for percent increase/decrease; multiplier recognition belongs in Unit 7-1.","question_html":"<section class=\"problem\" id=\"7-16\">\n<h2>7-16</h2>\n<div class=\"meta\"><span class=\"pill\">Review/Preview</span><span>Sorted to Unit 7, Section 2</span></div>\n<div class=\"audit\">Audit note: Converts percent increases and decreases into multiplicative growth or decay factors.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\">Write the multiplier for each increase or decrease described below.<strong> </strong></p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">A $25\\%$ increase\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\" style=\"\">A decrease of $18\\%$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p class=\"\" style=\"\">An increase of $39\\%$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p class=\"\" style=\"\">A decrease of $94\\%$\u00a0</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0018","original_source":"cpm-7-51","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"1","unit_section_title":"Unit 7, Section 1: Recognizing Growth & Decay","source_type":"Review/Preview","audit_status":"authoritative","notes":"Determines whether a sequence is arithmetic or geometric and identifies parameters.","question_html":"<section class=\"problem\" id=\"7-51\">\n<h2>7-51</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 1: Recognizing Growth &amp; Decay</div>\n<div class=\"audit\">Audit note: Determines a variable value so a sequence is arithmetic or geometric.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Consider the sequence $2, 8, 3y + 5$.\u00a0</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">Find the value of <em>$y$</em> if the sequence is arithmetic.</p></li><li><p class=\"\">Find the value of <em>$y$</em> if the sequence is geometric.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0019","original_source":"cpm-Types of Sequences","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Math Note","audit_status":"authoritative","notes":"Math Note defining arithmetic, geometric, and recursive sequences, including multipliers and notation.","question_html":"<div class=\"problem missing\"><h2>Types of Sequences</h2><p>Content block was not found in the uploaded source HTML, but this row is present in the authoritative audit CSV.</p></div>"},{"problem_id":"unit07-0020","original_source":"cpm-5-91","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Models percent increase with a multiplier and writes recursive and explicit exponential rules.","question_html":"<section class=\"problem\" id=\"5-91\">\n<h2>5-91</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Models percent increase with a multiplier and writes recursive and explicit exponential rules.</div>\n<div><div class=\"row\"><div class=\"col-sm-8\"><p>Thanks to the millions of teens around the world seeking to be just like their math teachers, industry analysts predict that sales of the new <em>$\\pi$</em>Phone will skyrocket! \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>The article provides a model for how many <em>$\\pi$</em>Phones the store expects to sell.  They start by selling $100$ <em>$\\pi$</em>Phone pre-orders in week zero.  Predict the number sold in the $4^{\\text{th}}$ week.</p></li><li><p>If you were to write the number of <em>$\\pi$</em>Phones the store received each week as a sequence, would your sequence be arithmetic, geometric, or something else?  Justify your answer.</p></li><li><p>The store needs to know how many phones to order for the last week of the year.  If you knew the number of <em>$\\pi$</em>Phones sold in week $51$ how could you find the sales for week $52$?  Write a recursive equation to show the predicted sales of <em>$\\pi$</em>Phones in the <em>n</em><sup>th</sup> week.</p></li><li><p>Write an explicit equation that starts with \u201c<em>$t(n) =$</em>\u201d to find the number of <em>$\\pi$</em>Phones sold during the <em>$n^\\text{th}$</em> week without finding all of the weeks in between.</p></li><li><p>How many <em>$\\pi$</em>Phones will the store predict it sells in the $52^{\\text{nd}}$ week?</p></li></ol></div><div class=\"col-sm-4\"><table><tbody><tr><td><p><strong>$\\boldsymbol{\\pi}$PHONES SWEEP THE NATION</strong></p><p><em>Millions demand one!</em></p></td></tr><tr><td><p>(API) \u2013 Teenagers and Hollywood celebrities flocked to an exclusive shop in Beverly Hills, California yesterday, clamoring for the new <em>$\\pi$</em>Phone. The store expects to start by selling $100$ and expects to sell an average of $15\\%$ more each week after that.</p><p>\u201cI plan to stand in line all night!\u201d said Nelly Hillman. \u201cAs soon as I own one, I\u2019ll be cooler than everyone else.\u201d</p><p>Across the globe, millions of fans</p></td></tr></tbody></table></div></div></div>\n</section>"},{"problem_id":"unit07-0021","original_source":"cpm-5-92","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Writes explicit and recursive rules for geometric growth using percent-increase multipliers.","question_html":"<section class=\"problem\" id=\"5-92\">\n<h2>5-92</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes explicit and recursive rules for geometric growth using percent-increase multipliers.</div>\n<div><p> A new <em>$\\pi$</em>Roid, a rival to the <em>$\\pi$</em>Phone, is about to be introduced.  It is cheaper than the <em>$\\pi$</em>Phone, so more are expected to sell.  The manufacturer plans to make and then sell $10{,}000$ pre-orders in week zero and expects sales to increase by $7\\%$ each week. \t</p><ol class=\"lower-alpha\"><li><p>Write an explicit and a recursive equation for the number of <em>$\\pi$</em>Roids sold during the <em>$n^{\\text{th}}$</em> week.</p></li><li><p>What if the expected weekly sales increase were $17\\%$ instead of $7\\%$?  Now what would the new explicit equation be?  How would it change the recursive equation?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0022","original_source":"cpm-5-93","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Writes explicit and recursive rules for exponential decay using a percent-decrease multiplier.","question_html":"<section class=\"problem\" id=\"5-93\">\n<h2>5-93</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes explicit and recursive rules for exponential decay using a percent-decrease multiplier.</div>\n<div><p>Oh no!  Thanks to the lower price, $10{,}000$ <em>$\\pi$</em>Roids were made and sold initially, but after that, weekly sales actually decreased by $3\\%$.</p><p>Find an explicit and a recursive equation that models the product\u2019s actual weekly sales.</p></div>\n</section>"},{"problem_id":"unit07-0023","original_source":"cpm-5-96","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Writes explicit and recursive equations from geometric tables, including shifted table patterns.","question_html":"<section class=\"problem\" id=\"5-96\">\n<h2>5-96</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes explicit and recursive equations from geometric tables, including shifted table patterns.</div>\n<div><p> Write an explicit and a recursive equation for each table below.  Be sure to check that your equations work for all of the entries in the table.</p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th><p><em>n</em></p></th><th><p><em>t(n)</em></p></th></tr><tr><td><p>$0$</p></td><td><p>$1600$</p></td></tr><tr><td><p>$1$</p></td><td><p>$2000$</p></td></tr><tr><td><p>$2$</p></td><td><p>$2500$</p></td></tr><tr><td><p>$3$</p></td><td><p>$3125$</p></td></tr><tr><td><p>$4$</p></td><td><p>$3906.25$</p></td></tr></tbody></table></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th><p><em>$n$</em></p></th><th><p><em>$t(n)$</em></p></th></tr><tr><td><p>$0$</p></td><td><p>$3906.25$</p></td></tr><tr><td><p>$1$</p></td><td><p>$3125$</p></td></tr><tr><td><p>$2$</p></td><td><p>$2500$</p></td></tr><tr><td><p>$3$</p></td><td><p>$2000$</p></td></tr><tr><td><p>$4$</p></td><td><p>$1600$</p></td></tr></tbody></table></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><table><tbody><tr><th><p><em>$n$</em></p></th><th><p><em>$t(n)$</em></p></th></tr><tr><td><p>$0$</p></td><td><p>$50$</p></td></tr><tr><td><p>$1$</p></td><td><p>$72$</p></td></tr><tr><td><p>$2$</p></td><td><p>$103.68$</p></td></tr><tr><td><p>$3$</p></td><td><p>$149.2992$</p></td></tr></tbody></table></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><table><tbody><tr><th><p><em>$n$</em></p></th><th><p><em>$t(n)$</em></p></th></tr><tr><td><p>$0$</p></td><td></td></tr><tr><td><p>$1$</p></td><td><p>$50$</p></td></tr><tr><td><p>$2$</p></td><td></td></tr><tr><td><p>$3$</p></td><td><p>$72$</p></td></tr><tr><td><p>$4$</p></td><td></td></tr><tr><td><p>$5$</p></td><td><p>$103.68$</p></td></tr><tr><td><p>$6$</p></td><td></td></tr><tr><td><p>$7$</p></td><td><p>$149.2992$</p></td></tr></tbody></table></li></ol></div></div><ol class=\"lower-alpha\" start=\"5\" type=\"a\"><li><p>How are the tables in (a) and (b) related?  How are the multipliers for (a) and (b) related?  Why does this make sense?</p></li></ol><ol class=\"lower-alpha\" start=\"6\" type=\"a\"><li><p>What strategies did you use to find the equation for part (d)?  How is the table in part (d) related to the one in part (c)?</p></li><li><p>In part (d), why is term $2$ <em>not</em> $61$?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0024","original_source":"cpm-5-101","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Completes exponential tables and writes equations from geometric patterns.","question_html":"<section class=\"problem\" id=\"5-101\">\n<h2>5-101</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Completes exponential tables and writes equations from geometric patterns.</div>\n<div><p>For each table below, find the missing entries and write an equation. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/tybditbpez\" rel=\"noopener\" target=\"_blank\">5-101 HW Help eTool</a> </p><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th><p>Month $\\left(x\\right)$</p></th><td><p>$0$</p></td><td><p>$1$</p></td><td><p>$2$</p></td><td><p>$3$</p></td><td><p>$4$</p></td><td><p>$5$</p></td><td><p>$6$</p></td></tr><tr><th><p>Population $(y)$</p></th><td><p>$2$</p></td><td><p>$8$</p></td><td><p>$32$</p></td><td></td><td></td><td></td><td></td></tr></tbody></table></li></ol><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th><p>Year $\\left(x\\right)$</p></th><td><p>$0$</p></td><td><p>$1$</p></td><td><p>$2$</p></td><td><p>$3$</p></td><td><p>$4$</p></td><td><p>$5$</p></td><td><p>$6$</p></td></tr><tr><th><p>Population$(y)$</p></th><td><p>$5$</p></td><td><p>$6$</p></td><td><p>$7.2$</p></td><td></td><td></td><td></td><td></td></tr></tbody></table></li></ol></div>\n</section>","resources":[{"label":"5-101 HW Help eTool","href":"https://www.desmos.com/calculator/tybditbpez"}]},{"problem_id":"unit07-0025","original_source":"cpm-notes","source_lesson":"5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem math-note\" id=\"notes\">\n<h2>Types of Sequences</h2>\n<div class=\"tagline\"><span class=\"pill\">Math Notes</span> Methods and Meanings</div>\n<div class=\"audit\">Audit note: Defines arithmetic, geometric, and recursive sequences, including percent multipliers and alternate sequence notation.</div>\n<p>An <strong>arithmetic sequence</strong> is a sequence with an addition or subtraction generator. The number added to each term to get the next term is called the <strong>common difference</strong>.</p>\n<p>A <strong>geometric sequence</strong> is a sequence with a multiplication or division generator. The number multiplied by each term to get the next term is called the <strong>common ratio</strong> or the <strong>multiplier</strong>.</p>\n<p>A multiplier can also be used to increase or decrease by a given percentage. For example, the multiplier for an increase of $7\\%$ is $1.07$. The multiplier for a decrease of $7\\%$ is $0.93$.</p>\n<p>A <strong>recursive sequence</strong> is a sequence in which each term depends on the term(s) before it. The equation of a recursive sequence requires at least one term to be specified. A recursive sequence can be arithmetic, geometric, or neither.</p>\n<p>For example, the sequence $-1, 2, 5, 26, 677, \\ldots$ can be defined by the recursive equation:</p>\n<p style=\"text-align:center;\">$t(1)=-1,\\ t(n+1)=(t(n))^2+1$</p>\n<p>An alternative notation for the equation of the sequence above is:</p>\n<p style=\"text-align:center;\">$a_1=-1,\\ a_{n+1}=(a_n)^2+1$</p>\n</section>"},{"problem_id":"unit07-0026","original_source":"cpm-5-115","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Determines a geometric sequence using initial value and multiplier structure.","question_html":"<section class=\"problem\" id=\"5-115\">\n<h2>5-115</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Determines a geometric sequence from an initial term and the sum of early terms using multiplier structure.</div>\n<div><p><strong>Additional Challenge:\u00a0</strong>Khalil is working with a geometric sequence. He knows that\u00a0<em>$t(0) = 3$</em> and that the sum of the first three terms <em>$(t(0), t(1),$</em> and\u00a0<em>$t(2))$</em>\u00a0is $63$. Help him figure out the sequence. Be prepared to share your\u00a0strategies\u00a0with the class.</p></div>\n</section>"},{"problem_id":"unit07-0027","original_source":"cpm-5-117","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Determines whether an exponential sequence can reach a target value and identifies the term.","question_html":"<section class=\"problem\" id=\"5-117\">\n<h2>5-117</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Determines whether an exponential sequence can reach a target value and identifies the term if possible.</div>\n<div><p>Is it possible for the sequence <em>$t(n) = 5 \\cdot  2^{n}$ </em>to have a term with the value of $200$? If so, which term is it? If not, justify why not.\u00a0\u00a0</p></div>\n</section>"},{"problem_id":"unit07-0028","original_source":"cpm-CL5-125","source_lesson":"Chapter 5 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Writes sequence equations from tables; mixed arithmetic/geometric item with geometric equation-writing focus.","question_html":"<div class=\"card\">\n<div class=\"problem-title\">CL 5-125</div>\n<p>Find an equation to represent each table as a sequence.</p>\n<div class=\"grid-2\">\n<ol type=\"a\"><li>\n<table aria-label=\"Table for CL 5-125 part a\">\n<tr><th>$n$</th><th>$t(n)$</th></tr>\n<tr><td>$1$</td><td>$4$</td></tr>\n<tr><td>$2$</td><td>$1$</td></tr>\n<tr><td>$3$</td><td>$-2$</td></tr>\n<tr><td>$4$</td><td></td></tr>\n</table>\n</li></ol>\n<ol start=\"2\" type=\"a\"><li>\n<table aria-label=\"Table for CL 5-125 part b\">\n<tr><th>$n$</th><th>$t(n)$</th></tr>\n<tr><td>$1$</td><td>$6$</td></tr>\n<tr><td>$2$</td><td>$7.2$</td></tr>\n<tr><td>$3$</td><td>$8.64$</td></tr>\n<tr><td>$4$</td><td></td></tr>\n</table>\n</li></ol>\n</div>\n</div>"},{"problem_id":"unit07-0029","original_source":"cpm-CL5-130","source_lesson":"Chapter 5 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Creates explicit equations for recursively defined sequences; mixed arithmetic/geometric item with recursive/geometric equation focus.","question_html":"<div class=\"card\">\n<div class=\"problem-title\">CL 5-130</div>\n<p>Create an explicit equation for each recursively-defined sequence below.</p>\n<ol type=\"a\">\n<li>$a_1=17$, $a_{n+1}=a_n-7$</li>\n<li>$t(1)=3$, $t(n+1)=5\\cdot t(n)$</li>\n</ol>\n</div>"},{"problem_id":"unit07-0030","original_source":"cpm-6-17","source_lesson":"6.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Identifies a geometric sequence, finds a later term, and writes an explicit exponential rule.","question_html":"<section class=\"problem\" id=\"6-17\">\n<h2>6-17</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Identifies a geometric sequence, finds a later term, and writes an explicit exponential rule.</div>\n<div><p>For this sequence $5,25,125,625, \u2026$.\u00a0</p><ol class=\"lower-alpha\" type=\"a\"><li><p>What kind of sequence is it?</p></li><li><p>Find the fifth term, <em>$a_{5}$</em>.</p></li><li><p>Write an explicit equation for the general term, <em>$a_{n} =$</em> ?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0031","original_source":"cpm-6-25","source_lesson":"6.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes an explicit exponential rule from a graphed geometric sequence.","question_html":"<section class=\"problem\" id=\"6-25\">\n<h2>6-25</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an explicit exponential rule from a graphed geometric sequence.</div>\n<div><div class=\"row\"><div class=\"col-sm-9\"><p>Write an explicit equation for the sequence based on the graph at right.\u00a0\u00a0</p></div><div class=\"col-sm-3\"><p><strong><img alt=\"A first quadrant coordinate plane with the x-axis labeled N and the y-axis labeled T of N. The discrete graph includes the points: (1, comma 12), (2, comma 36), (3, comma 108).\" class=\"figure-img\" src=\"assets/6-25.png\"/></strong></p></div></div></div>\n</section>"},{"problem_id":"unit07-0032","original_source":"cpm-6-36","source_lesson":"6.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses percent increase to identify a multiplier, make an exponential prediction, and write an equation.","question_html":"<section class=\"problem\" id=\"6-36\">\n<h2>6-36</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses percent increase to identify a multiplier, make an exponential prediction, and write an equation.</div>\n<div><p>An item currently costing $20 is increasing in cost by 5% per year. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>What is the multiplier?</p></li><li><p>What will the item cost five years from now?</p></li><li><p>Write an equation to find the cost in <em>n </em>years.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0033","original_source":"cpm-6-44","source_lesson":"6.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses percent decrease to identify a multiplier, make an exponential prediction, and write an equation.","question_html":"<section class=\"problem\" id=\"6-44\">\n<h2>6-44</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses percent decrease to identify a multiplier, make an exponential prediction, and write an equation.</div>\n<div><p>The cost of a $55$ inch HDTV is decreasing $15\\%$ per year. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>What is the multiplier?</p></li><li><p>If the current cost of the HDTV is $\\$1500$, what will it cost in four years?</p></li><li><p>If the current cost of the HDTV is $\\$1500$, write an equation for the cost in <em>$n$</em> years.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0034","original_source":"cpm-6-46","source_lesson":"6.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Converts recursive arithmetic and geometric sequences to explicit equations, including an exponential sequence.","question_html":"<section class=\"problem\" id=\"6-46\">\n<h2>6-46</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Converts recursive arithmetic and geometric sequences to explicit equations, including an exponential sequence.</div>\n<div><p>For each sequence defined recursively, write the first few terms. Then use the terms to write an explicit equation. </p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p>\u00a0$a_1=17$<br/>$a_{n+1}=a_n-3$</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>\u00a0$a_1=20$<br/>$a_{n+1}=\\frac{1}{2}\\cdot a_n$</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0035","original_source":"cpm-6-56","source_lesson":"6.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes an explicit equation for a geometric sequence from a discrete graph.","question_html":"<section class=\"problem\" id=\"6-56\">\n<h2>6-56</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an explicit equation for a geometric sequence from a discrete graph.</div>\n<div><div class=\"row\"><div class=\"col-sm-8\"><p>Write an explicit equation for the sequence graphed at right.\u00a0\u00a0</p></div></div></div>\n<div class=\"captured-figures\"><figure><img alt=\"Captured figure for 6-56\" class=\"figure-img\" src=\"assets/6-56.png\"/><figcaption>Captured figure for 6-56</figcaption></figure></div>\n</section>"},{"problem_id":"unit07-0036","original_source":"cpm-6-76","source_lesson":"6.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Finds a geometric monthly multiplier and percent increase from an initial and final value.","question_html":"<section class=\"problem\" id=\"6-76\">\n<h2>6-76</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Finds a geometric monthly multiplier and percent increase from an initial and final value.</div>\n<div><p>During a two-month period gasoline increased from $\\$4.10$ per gallon to $\\$4.35$ per gallon. Assuming prices increased in a geometric sequence, what was the monthly multiplier and what was the percent increase? </p></div>\n</section>"},{"problem_id":"unit07-0037","original_source":"cpm-6-89","source_lesson":"6.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Classifies a geometric sequence, describes its graph, and writes an explicit exponential rule.","question_html":"<section class=\"problem\" id=\"6-89\">\n<h2>6-89</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Classifies a geometric sequence, describes its graph, and writes an explicit exponential rule.</div>\n<div><p>Given the sequence $2, 10, 50, 250, \u2026$ complete parts (a) through (c) below. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>What kind of sequence is it?</p></li><li><p>Describe the shape of the graph.</p></li><li><p>Give an explicit equation for the sequence.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0038","original_source":"cpm-6-112","source_lesson":"6.2.5","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses recursive notation for a geometric sequence and writes an explicit exponential rule.","question_html":"<section class=\"problem\" id=\"6-112\">\n<h2>6-112</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses recursive notation for a geometric sequence and writes an explicit exponential rule.</div>\n<div><div><p>For the recursively defined sequence: $$\\begin{array}{l}a_1=5\\\\a_n=-2\\cdot a_{n-1}\\end{array}$$</p><ol class=\"lower-alpha\" type=\"a\"><li><p>List the first five terms of the sequence.</p></li><li><p>Write an explicit equation for the sequence.</p></li></ol></div></div>\n</section>"},{"problem_id":"unit07-0039","original_source":"cpm-CL6-128","source_lesson":"Chapter 6 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Multiplier, explicit equation, and recursive equation for a geometric sequence.","question_html":"<div class=\"card problem\" id=\"CL6-128\">\n<div class=\"problem-title\">CL 6-128</div>\n<div class=\"with-figure\">\n<div>\n<p>Use the graph at right to complete parts (a) through (c) below.</p>\n<ol type=\"a\">\n<li>What is the multiplier for this sequence?</li>\n<li>Write an explicit equation for this sequence.</li>\n<li>Write a recursive equation for this sequence.</li>\n</ol>\n</div>\n<img alt=\"Discrete graph of points (1, 6), (2, 18), and (3, 54).\" class=\"figure\" src=\"assets/cl-6-128.png\"/>\n</div>\n</div>"},{"problem_id":"unit07-0040","original_source":"cpm-7-10","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes and uses a geometric/exponential decay rule for rebound height.","question_html":"<section class=\"problem\" id=\"7-10\">\n<h2>7-10</h2>\n<div class=\"meta\"><span class=\"pill\">Review/Preview</span><span>Sorted to Unit 7, Section 2</span></div>\n<div class=\"audit\">Audit note: Writes and uses a geometric/exponential decay rule for rebound height.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\">If a ball is dropped from $160$ cm and rebounds to $120$ cm on the first bounce, how high will the ball be: </p><ol class=\"lower-alpha\"><li><p class=\"\" style=\"\">On the $2^{nd}$ bounce?</p></li></ol><ol class=\"lower-alpha\" start=\"2\"><li><p class=\"\" style=\"\">On the $5^{th}$ bounce?</p></li></ol><ol class=\"lower-alpha\" start=\"3\"><li><p class=\"\" style=\"\">On the <em>$n^{th}$</em> bounce?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0041","original_source":"cpm-7-20","source_lesson":"7.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Connects tables, situations, and equations using initial value and multiplier.","question_html":"<section class=\"problem\" id=\"7-20\">\n<h2>7-20</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Connects tables, situations, and equations for exponential models using starting value and multiplier.</div>\n<div><div><div><p>Let\u2019s look at some of the connections between the multiple representations of an exponential function.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Arnold dropped a ball during the bouncing ball activity and recorded its height in a table. Part of his table is shown at right. What was the rebound ratio of his ball? At what height did he drop the ball? Write an equation that represents his data. Explain your equation.</p></li></ol></div><div><table><tbody><tr><th><p>Bounce<br/>Number</p></th><th><p>Height <br/>(cm)</p></th></tr><tr><td><p>$0$<br/></p></td><td></td></tr><tr><td><p>$1$</p></td><td></td></tr><tr><td><p>$2$</p></td><td><p>$84.5$</p></td></tr><tr><td><p>$3$</p></td><td><p>$67.6$</p></td></tr><tr><td><p>$4$</p></td><td><p>$54.1$</p></td></tr></tbody></table></div></div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p> A major technology company, ExpoGrow, is growing incredibly fast. The latest prospectus (a report on the company) said that so far, the number of employees, <em>$y$</em>, could be found with the equation <em>$y = 3\\left(4\\right)^{x}$</em>, where <em>x</em> represents the number of years since the company was founded. How many people founded the company? How can the growth of this company be described?</p></li></ol><div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>A computer virus is affecting the technology center in such a way that each day, a certain portion of virus-free computers is infected. The number of virus-free computers is recorded in the table at right. How many computers are in the technology center? What portion of virus-free computers is infected each day? How many computers will remain virus-free at the end of the third day? Justify your answer.</p></li></ol></div><div><table><tbody><tr><th><p>Day</p></th><th><p>Uninfected<br/> \t\t\t\t\tComputers</p></th></tr><tr><td><p>$0$<br/></p></td><td><p>$27$<br/></p></td></tr><tr><td><p>$1$</p></td><td><p>$18$</p></td></tr><tr><td><p>$2$</p></td><td><p>$12$</p></td></tr></tbody></table></div></div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>As part of a major scandal, it was discovered that several statements in the prospectus for ExpoGrow in part (b) were false. If the company actually had five founders and doubles in size each year, what equation should it have printed in its report?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0042","original_source":"cpm-7-21","source_lesson":"7.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Interprets parameters a and b across representations.","question_html":"<section class=\"problem\" id=\"7-21\">\n<h2>7-21</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Interprets the parameters a and b in y=ab^x across representations.</div>\n<div><p>Most of the exponential equations you have used in this chapter have been in the form <em>$y = ab^{x}$</em>. Explore using the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/dhfdregqbs\" rel=\"noopener\" target=\"_blank\">7-21 Student eTool</a>. Click in the lower right corner of the graph to view it in full-screen mode.</p><div><div><div><img alt=\"Captured figure for 7-21\" class=\"figure-img\" src=\"assets/7-21.png\"/></div></div><div><ol class=\"lower-alpha\" type=\"a\"><li><p>What does <em>a</em> represent in this equation? What does <em>b</em> represent?</p></li><li><p>How can you identify <em>a</em> by looking at a table? How can you find it in a situation? Give an example for each representation.</p></li><li><p>How can you determine <em>b</em> in each representation? Use arrows or colors to add your ideas about <em>b</em> to the examples you created in part (b).</p></li></ol></div></div></div>\n</section>","resources":[{"label":"7-21 Student eTool","href":"https://www.desmos.com/calculator/dhfdregqbs"}]},{"problem_id":"unit07-0043","original_source":"cpm-7-24","source_lesson":"7.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Completes exponential tables and writes equations in y=ab^x form.","question_html":"<section class=\"problem\" id=\"7-24\">\n<h2>7-24</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Completes exponential tables and writes equations of the form y=ab^x.</div>\n<div><p>Each table below represents an exponential function of the form <em>$y=ab^x$</em>. Copy and complete each table on your paper and find the corresponding equation.</p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th><p><em> x</em></p></th><th><p><em>y</em></p></th></tr><tr><td><p>$0$</p></td><td><p>$1.2$</p></td></tr><tr><td><p>$1$</p></td><td><p>$3.96$</p></td></tr><tr><td><p>$2$</p></td><td><p>$13.068$</p></td></tr><tr><td><p>$3$</p></td><td></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th><p><em> x</em></p></th><th><p><em>y</em></p></th></tr><tr><td><p>$0$</p></td><td><p>$5$</p></td></tr><tr><td><p>$1$</p></td><td></td></tr><tr><td><p>$2$</p></td><td><p>$180$</p></td></tr><tr><td><p>$3$</p></td><td></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0044","original_source":"cpm-7-36","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Completes exponential tables and writes equations in y=ab^x form.","question_html":"<section class=\"problem\" id=\"7-36\">\n<h2>7-36</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Completes exponential tables and writes equations in y=ab^x form.</div>\n<div><p>Each table below represents an exponential function in <em>$y=ab^x$</em>form. Copy and complete each table on your paper and find a corresponding equation.</p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th><p><em> x</em></p></th><th><p><em>y</em></p></th></tr><tr><td><p>$\u20131$</p></td><td><p>$3$</p></td></tr><tr><td><p>$0$</p></td><td></td></tr><tr><td><p>$1$</p></td><td><p>$75$</p></td></tr><tr><td><p>$2$</p></td><td></td></tr><tr><td><p>$3$</p></td><td></td></tr></tbody></table></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th><p><em>   x</em></p></th><th><p><em>  y</em></p></th></tr><tr><td><p> $0$</p></td><td></td></tr><tr><td><p> $1$</p></td><td></td></tr><tr><td><p>$2$</p></td><td><p>$96.64$</p></td></tr><tr><td><p>$3$</p></td><td><p>$77.312$</p></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0045","original_source":"cpm-7-59","source_lesson":"7.1.5","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Uses graphical clues to determine a and b and write equations in y=ab^x form.","question_html":"<section class=\"problem\" id=\"7-59\">\n<h2>7-59</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses graph clues such as intercepts, points, and multipliers to write exponential equations in y=ab^x form.</div>\n<div><p>GRAPH \u2192 EQUATION<br/> \tUse the clues provided in each graph below to find a possible corresponding equation in <em>$y = ab^{x}$</em> form. Assume that if the graph has an asymptote, it is located on the <em>$x$</em>-axis.</p><div><img alt=\"Captured graph-to-equation figures for 7-59, parts a through f.\" class=\"figure-img wide-figure\" src=\"assets/7-59.png\"/></div></div>\n</section>"},{"problem_id":"unit07-0046","original_source":"cpm-7-60","source_lesson":"7.1.5","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Learning Log","audit_status":"authoritative","notes":"Summarizes methods for creating exponential equations from graphs.","question_html":"<section class=\"problem\" id=\"7-60\">\n<h2>7-60</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Summarizes methods for creating exponential equations from graphs.</div>\n<div><div><div><p>LEARNING LOG</p><p>Create a Learning Log entry in which you describe methods for creating an exponential equation given a graph. Be sure to include examples to illustrate your reasoning. Title this entry \u201cGraph \u2192  Equation for Exponential Functions\u201d and label it with today\u2019s date.</p></div><div></div></div></div>\n</section>"},{"problem_id":"unit07-0047","original_source":"cpm-7-62","source_lesson":"7.1.5","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses graph clues to determine an exponential equation.","question_html":"<section class=\"problem\" id=\"7-62\">\n<h2>7-62</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses a graph with a starting value and multiplier clue to write an exponential equation.</div>\n<div><div><div><p>Use the clues in the graph at right to find a possible corresponding equation in <em>$y=ab^x$</em>form. Assume the graph has an asymptote at the <em>$x$</em>-axis.</p></div><div><p><img alt=\"Captured graph for 7-62.\" class=\"figure-img\" src=\"assets/7-62.png\"/></p></div></div></div>\n</section>"},{"problem_id":"unit07-0048","original_source":"cpm-7-74","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Solves for a and b in exponential equations.","question_html":"<section class=\"problem\" id=\"7-74\">\n<h2>7-74</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Solves for the initial value and multiplier in exponential equations using given output values.</div>\n<p>Find values of <em>$a$</em> and <em>$b$</em> that make each system of equations true (i.e., solve each system). Be sure to show your work or explain your thinking clearly.</p>\n<div class=\"row\">\n<div><ol class=\"lower-alpha\" type=\"a\"><li><p>$6=a\\cdot b^0$<br/>$24=a\\cdot b^2$</p></li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$32=a\\cdot b^2$<br/>$128=a\\cdot b^3$</p></li></ol></div>\n</div>\n</section>"},{"problem_id":"unit07-0049","original_source":"cpm-7-80","source_lesson":"7.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Uses graph information to determine a and b in y=ab^x.","question_html":"<section class=\"problem\" id=\"7-80\">\n<h2>7-80</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses an exponential graph with two points to identify a and solve for b in y=ab^x.</div>\n<div><div><div><p>Can you use a similar idea to find an exponential equation in <em>$y=ab^x$<sup></sup></em>form?</p><ol class=\"lower-alpha\" type=\"a\"><li><p>While trying to find the equation for the graph in part (c) of problem 7-59 (shown again at right), Errol stated, <em>\u201cI think \u2018a\u2019 must be $\\mathit{7}$ because the $\\it y$-intercept is at $\\mathit{(0, 7)}$.\u201d</em> Do you agree? Justify your answer.</p></li><li><p><em>\u201cBut we still don\u2019t know what \u201c$b$\u201d is,\u201d</em> Errol noticed. His teammate, Sandy, had an idea. <em>\u201cI think that</em> $56 = 7\\left(b\\right)^{3}$<em>.\u201d</em> How did she get this equation? Is it valid? Explain.</p></li><li><p>If you have not done so already, solve $56=7(b)^3$ for <em>b</em>. Explain how you solved this equation.</p></li><li><p>Use <em>a</em> and <em>b</em> to write the equation for this graph. Does it agree with the equation you found in part (c) of problem 7-59?</p></li></ol></div><div><p><img alt=\"Captured exponential graph for 7-80.\" class=\"figure-img\" src=\"assets/7-80.png\"/></p></div></div></div>\n</section>"},{"problem_id":"unit07-0050","original_source":"cpm-7-81","source_lesson":"7.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Writes exponential equations from two points.","question_html":"<section class=\"problem\" id=\"7-81\">\n<h2>7-81</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an exponential equation from two points by using the initial value and solving for the growth factor.</div>\n<div><p> Use Errol\u2019s and Sandy\u2019s method from problem 7-80 to find the equation of an exponential function with an asymptote at <em>$y=0$</em> that passes through the points $\\left(0, 5\\right)$ and $\\left(3, 320\\right)$.</p></div>\n</section>"},{"problem_id":"unit07-0051","original_source":"cpm-7-87","source_lesson":"7.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Finds exponential equations from points.","question_html":"<section class=\"problem\" id=\"7-87\">\n<h2>7-87</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes exponential functions in y=ab^x form from an initial value and another point.</div>\n<div><p>Find a possible exponential function in <em>$y=a\u00b7b^x$</em>form that represents each situation described below.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Has an initial value of $2$ and passes through the point $\\left(3, 128\\right)$.</p></li><li><p>Passes through the points $\\left(0, 4\\right)$ and $\\left(2, 1\\right)$.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0052","original_source":"cpm-7-88","source_lesson":"7.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Solves for a and b in exponential systems.","question_html":"<section class=\"problem\" id=\"7-88\">\n<h2>7-88</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Solves small systems involving a and b to determine exponential equations.</div>\n<div><p>Solve the following systems of equations. In other words, find values of <em>$a$</em> and <em>$b$</em> that make each system true. Be sure to show your work or explain your thinking clearly.</p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><p> $3=a\u00b7b^0$ <br/>$75=a\u00b7b^2$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p> $18=a\u00b7b^2$ <br/>$54=a\u00b7b^3$</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0053","original_source":"cpm-7-94","source_lesson":"7.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Extends the two-point method to exponential equations in y=ab^x.","question_html":"<section class=\"problem\" id=\"7-94\">\n<h2>7-94</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Extends the two-point substitution/system method to exponential equations in $y=ab^x$.</div>\n<div><p>Can Mitchell\u2019s method from problem 7-92 be used to find the <em>exponential</em> function that passes through the points $(2, 16)$ and $(6, 256)$? Consider this as you answer the questions below.</p>\n<ol class=\"lower-alpha\" type=\"a\"><li><p>What is the general form for an exponential function that has an asymptote at <em>$y = 0$</em>?</p></li><li><p>Use the two points that you know to create a system of equations.</p></li><li><p>Solve both equations for <em>$a$</em>. Then use the Equal Values Method to solve your system of equations for <em>$b$</em>. Find <em>a</em>, and write the equation that goes through the two points.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0054","original_source":"cpm-7-95","source_lesson":"7.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Finds exponential equations from pairs of points.","question_html":"<section class=\"problem\" id=\"7-95\">\n<h2>7-95</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Finds exponential functions from pairs of points, including negative and fractional values.</div>\n<div><p>Find an exponential function that passes through each pair of points.</p>\n<div class=\"row\"><div><ol class=\"lower-alpha\" type=\"a\"><li><p>$(-1, -2)$ and $(3, -162)$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$(2, 1.75)$ and $(-2, 28)$</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0055","original_source":"cpm-7-96","source_lesson":"7.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Continues exponential curve fitting from two points.","question_html":"<section class=\"problem\" id=\"7-96\">\n<h2>7-96</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Continues exponential curve fitting from two points in $y=ab^x$ form.</div>\n<div><p>Find an exponential function that passes through each pair of points.</p>\n<div class=\"row\"><div><ol class=\"lower-alpha\" type=\"a\"><li><p>$(1, 7.5)$ and $(3, 16.875)$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$(-1, 1.25)$ and $(3, 0.032)$</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0056","original_source":"cpm-7-106","source_lesson":"7.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Finds an exponential function from two points.","question_html":"<article class=\"problem\" id=\"7-106\">\n<h3>7-106.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 7, Section 2: Writing Exponential Equations</span></div>\n<div class=\"audit\">Audit note: Finds an exponential function from two points.</div>\n<p>Find the equation of an exponential function that passes through the points $(2,48)$ and $(5,750)$.</p>\n</article>"},{"problem_id":"unit07-0057","original_source":"cpm-CL7-112","source_lesson":"Chapter 7 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Finds exponential functions from a multiplier and from two points.","question_html":"<div class=\"card\" id=\"CL7112\">\n<div class=\"problem-title\">CL 7-112</div>\n<p>Find an exponential function in $y=ab^x$ form that satisfies each of the following sets of conditions.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>Has a $y$-intercept of $(0,2)$ and a multiplier of $0.8$.</li>\n<li>Passes through the points $(0,3.5)$ and $(2,31.5)$.</li>\n</ol>\n</div>"},{"problem_id":"unit07-0058","original_source":"cpm-8-108","source_lesson":"8.2.5","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Finds a monthly multiplier and percent increase from exponential growth.","question_html":"<section class=\"problem\" id=\"8-108\">\n<h2>8-108</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Finds a monthly multiplier and percent increase from exponential growth over four months.</div>\n<p>Over a four month period the price of an ounce of gold steadily increased from $1000 to $1400. What was the monthly multiplier? What was the monthly percent increase?</p>\n</section>"},{"problem_id":"unit07-0059","original_source":"cpm-CL8-121","source_lesson":"Chapter 8 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Explicit and recursive geometric sequence generation; geometric/exponential objective dominates.","question_html":"<div class=\"card\" id=\"CL8121\">\n<div class=\"problem-title\">CL 8-121</div>\n<p>Write the first four terms of the following sequences.</p>\n<div class=\"grid-2\">\n<ol type=\"a\"><li>$a_n=3\\cdot 5^{n-1}$</li></ol>\n<ol start=\"2\" type=\"a\"><li>$a_1=10,\\ a_{n+1}=-5a_n$</li></ol>\n</div>\n</div>"},{"problem_id":"unit07-0060","original_source":"cpm-9-11","source_lesson":"9.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential growth/decay equation writing.","question_html":"<section class=\"problem\" id=\"9-11\">\n<h2>9-11</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an equation for a geometric sequence from graphed ordered pairs.</div>\n<div><div class=\"two-col\"><div><p>Find an equation of the sequence represented by this graph.</p></div><div><img alt=\"Graph of a sequence with labeled points (4,12), (5,36), and (6,108).\" class=\"medium-img\" src=\"assets/9-11.png\"/></div></div></div>\n</section>"},{"problem_id":"unit07-0061","original_source":"cpm-9-22","source_lesson":"9.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes an exponential equation from percent growth information.","question_html":"<section class=\"problem\" id=\"9-22\">\n<h2>9-22</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Models percent increase with an exponential multiplier to predict a future cost.</div>\n<div><p>The increased demand for vegetarian meals has caused an increase in the price of tofu. If the current cost of $\\$2.99$ per pound is increasing $6\\%$ per year, what will it cost in $5$ years?</p></div>\n</section>"},{"problem_id":"unit07-0062","original_source":"cpm-9-43","source_lesson":"9.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential equation-writing task.","question_html":"<section class=\"problem\" id=\"9-43\">\n<h2>9-43</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses monthly compound interest to find a multiplier and future balance.</div>\n<div><p><strong>No Payments For The First Six Months!</strong></p>\n<p>You just bought a new tablet computer for $\\$500$ including tax. There are no required payments for six months but the company does charge $30\\%$ annual interest, compounded monthly, on any unpaid balance.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>What is the monthly multiplier?</p></li>\n<li><p>If you do not make any payments for six months, how much will you now owe for your new tablet?</p></li>\n</ol></div>\n</section>"},{"problem_id":"unit07-0063","original_source":"cpm-9-55","source_lesson":"9.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential equation-writing review.","question_html":"<section class=\"problem\" id=\"9-55\">\n<h2>9-55</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 6, Section 2: Solving Quadratics with Graphs and Square Roots</div>\n<div class=\"audit\">Audit note: Estimates x-intercepts from parabola graphs and confirms them using the Quadratic Formula. | Images: figures/9-55.png</div>\n<div><p>For each parabola graphed below, visually estimate the $x$-intercepts. Then use the Quadratic Formula to confirm your estimates.</p>\n<figure class=\"figure\"><img alt=\"Problem 9-55 two parabola graphs labeled a and b\" src=\"assets/9-55.png\"/><figcaption>Problem 9-55</figcaption></figure></div>\n</section>"},{"problem_id":"unit07-0064","original_source":"cpm-9-62","source_lesson":"9.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential equation writing from growth information.","question_html":"<section class=\"problem\" id=\"9-62\">\n<h2>9-62</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 3: Writing Linear Equations</div>\n<div class=\"audit\">Audit note: Writes the equation of a line from a slope and a point.</div>\n<div>\n<p>Find the equation of the line with slope $-\\frac{3}{5}$ passing through the point $(-6,2)$.</p></div>\n</section>"},{"problem_id":"unit07-0065","original_source":"cpm-9-72","source_lesson":"9.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes an exponential equation from two points.","question_html":"<section class=\"problem\" id=\"9-72\">\n<h2>9-72</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an exponential equation from two points using the form $y=ab^x$.</div>\n<div>\n<p>If the graph of an exponential function passes through the points $(1,6)$ and $(4,48)$, find an equation of the function. Refer to the Math Notes box in this lesson if you need help.</p></div>\n</section>"},{"problem_id":"unit07-0066","original_source":"cpm-CL9-131","source_lesson":"Chapter 9 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Finds an exponential equation from two points.","question_html":"<div class=\"card\" id=\"CL9131\">\n<div class=\"problem-title\">CL 9-131</div>\n<p>Find the equation of an exponential function of the form $y=ab^x$ that passes through the points $(3,13.5)$ and $(5,30.375)$.</p>\n</div>"},{"problem_id":"unit07-0067","original_source":"cpm-10-24","source_lesson":"10.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Solves exponential equations by rewriting bases.","question_html":"<section class=\"problem\" id=\"10-24\">\n<h2>10-24</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Other: Exponent Properties / Rewriting Exponential Equations</div>\n<div class=\"audit\">Audit note: Uses equivalent bases and power-of-a-power structure to solve exponential equations.</div>\n<p>Derek and Donovan were trying to solve the equation $4^4=16^x$. Derek had an idea.</p>\n<p><em>\u201cI know,\u201d</em> he said. <em>\u201cIsn\u2019t</em> $16$ <em>equal to</em> $4^2$<em>?\u201d</em></p>\n<p><em>\u201cYeah, so what?\u201d</em> said Donovan.</p>\n<p><em>\u201cThat means that we can rewrite the equation to look like</em> $4^4=(4^2)^x$<em>. This is much easier to solve!\u201d</em> replied Derek.</p>\n<p><em>\u201cYes,\u201d</em> said Donovan. <em>\u201cThat makes sense. Isn\u2019t there another way, too? Since</em> $4$ <em>is the same as</em> $2^2$ <em>and</em> $16$ <em>is the same as</em> $2^4$<em>, can\u2019t we rewrite it as</em> $(2^2)^4=(2^4)^x$<em>?\u201d</em></p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>What were Derek and Donovan thinking? Will both methods work?</li>\n<li>Use both methods to solve $4^4=16^x$.</li>\n<li>Solve $3^5=9^{2x}$.</li>\n</ol>\n</section>"},{"problem_id":"unit07-0068","original_source":"cpm-10-25","source_lesson":"10.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Lesson","audit_status":"authoritative","notes":"Common-base exponential equation solving.","question_html":"<section class=\"problem\" id=\"10-25\">\n<h2>10-25</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Other: Exponent Properties / Rewriting Exponential Equations</div>\n<div class=\"audit\">Audit note: Solves exponential equations by rewriting both sides with a common base and comparing exponents.</div>\n<p>Solve each equation below for $x$.</p>\n<div class=\"two-col\">\n<div><ol class=\"lower-alpha\" type=\"a\"><li>$2^{(x+3)}=2^{2x}$</li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$3^{(2x+1)}=3^3$</li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$9^x=3^{40}$</li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$8^{70}=2^x$</li></ol></div>\n</div>\n</section>"},{"problem_id":"unit07-0069","original_source":"cpm-10-33","source_lesson":"10.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"10-33\">\n<h2>10-33</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Finds an exponential function from two points by determining the multiplier and initial value.</div>\n<p>Find the equation of the exponential function $y=ab^x$ passing through the points $(2,3.84)$ and $(3,3.072)$. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/flmd3duho0\" rel=\"noopener\" target=\"_blank\">10-33 HW eTool</a></p>\n</section>","resources":[{"label":"10-33 HW eTool","href":"https://www.desmos.com/calculator/flmd3duho0"}]},{"problem_id":"unit07-0070","original_source":"cpm-10-44","source_lesson":"10.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"10-44\">\n<h2>10-44</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7: Exponential Functions and Modeling, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Finds parameters of an exponential function from two points.</div>\n<p>Find the equation of an exponential function of the form $y=ab^x$ passing through the points $(2,3)$ and $(5, \\frac{1}{9})$.</p>\n</section>"},{"problem_id":"unit07-0071","original_source":"cpm-10-53","source_lesson":"10.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Solves exponential equations by rewriting bases.","question_html":"<section class=\"problem\" id=\"10-53\">\n<h2>10-53</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Other: Exponent Properties / Rewriting Exponential Equations</div>\n<div class=\"audit\">Audit note: Solves exponential equations by rewriting both sides with the same base.</div>\n<p>Solve each equation by first rewriting the expressions in each part with the same base. Refer to problem 10-24 if you need a reminder.</p>\n<div class=\"three-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$8^x=2^6$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$9^2=3^{2x+1}$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$4^{2x}=\\left(\\frac{1}{2}\night)^{x+5}$</li></ol></div></div>\n</section>"},{"problem_id":"unit07-0072","original_source":"cpm-10-94","source_lesson":"10.2.6","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes exponential equation from two points.","question_html":"<section class=\"problem\" id=\"10-94\">\n<h2>10-94</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes an exponential function from two points and sketches the resulting graph. Useful eTool link kept.</div>\n<p>An exponential function of the form $f(x)=ab^x$ passes through the points $(2,2)$ and $\\left(4,\\frac{1}{2}\\right)$. <a class=\"resource\" href=\"https://www.desmos.com/calculator/h84eowdzfg\" rel=\"noopener\" target=\"_blank\">10-94 HW eTool (Desmos)</a></p>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>Find the equation of the function.</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>Use the equation to sketch a graph of the function.</li></ol></div></div>\n</section>","resources":[{"label":"10-94 HW eTool (Desmos)","href":"https://www.desmos.com/calculator/h84eowdzfg"}]},{"problem_id":"unit07-0073","original_source":"cpm-10-119","source_lesson":"10.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"10-119\">\n<h2>10-119</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Checkpoint, Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Checkpoint 10A for the exponential web: graph, write an equation from a table, and write context from an equation; keeps checkpoint link.</div>\n<p>This problem is a checkpoint for the exponential web. It will be referred to as <strong>Checkpoint 10A</strong>.</p><p>Use the given part of the exponential web and create the desired part.</p><div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>Graph $y=2(0.75)^x$.</li><li>Write the equation for the exponential function based on the table at right.</li><li>Write a possible context based on the equation $f(x)=75(0.85)^x$.</li></ol><p>Check your answers by referring to the <a class=\"resource\" href=\"/bookdb.php?title=cca&amp;name=reference.checkpoints&amp;type=tcheckpoints&amp;section=13\" target=\"_self\">Checkpoint 10A: The Exponential Web</a> materials located at the back of your book.</p></div><div class=\"scroll-table\"><table><thead><tr><th>$x$</th><th>$f(x)$</th></tr></thead><tbody><tr><td>1</td><td>23</td></tr><tr><td>2</td><td>52.9</td></tr><tr><td>3</td><td>121.67</td></tr><tr><td>4</td><td></td></tr></tbody></table></div></div>\n</section>"},{"problem_id":"unit07-0074","original_source":"cpm-CL10-148","source_lesson":"Chapter 10 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Builds exponential equation from two function values.","question_html":"<div class=\"card\" id=\"CL10148\">\n<div class=\"problem-title\">CL 10-148</div>\n<p>For an exponential function of the form $f(x)=ab^x$, $f(3)=24$ and $f(4)=48$. Find an equation that matches this data.</p>\n</div>"},{"problem_id":"unit07-0075","original_source":"cpm-11-47","source_lesson":"11.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes equations for linear and geometric sequences; exponential-writing strand dominates.","question_html":"<section class=\"problem\" id=\"11-47\">\n<h2>11-47</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 2: Writing Exponential Equations</div>\n<div class=\"audit\">Audit note: Writes equations for sequences represented by tables, including linear and geometric growth patterns.</div>\n<p>Find an equation for each sequence.</p>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li><table class=\"data\"><tbody><tr><th>$n$</th><th>$t(n)$</th></tr><tr><td>1</td><td>7</td></tr><tr><td>2</td><td>4</td></tr><tr><td>3</td><td>1</td></tr></tbody></table></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table class=\"data\"><tbody><tr><th>Year</th><th>Cost</th></tr><tr><td>2</td><td>$2000</td></tr><tr><td>3</td><td>$6000</td></tr><tr><td>4</td><td>$18000</td></tr></tbody></table></li></ol></div></div>\n</section>"},{"problem_id":"unit07-0076","original_source":"cpm-CL11-145b","source_lesson":"Chapter 11 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Closure","audit_status":"authoritative","notes":"Writes an exponential equation through two points.","question_html":"<div class=\"card\" id=\"CL11145\">\n<div class=\"problem-title\">CL 11-145</div>\n<p>For the points $(-1,18)$ and $(1,2)$ determine:</p>\n<ol type=\"a\">\n<li>An equation of a line passing through the points.</li>\n<li>An equation of an exponential function passing through the points.</li>\n</ol>\n</div>"},{"problem_id":"unit07-0077","original_source":"cpm-CP10A-05","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Write an exponential equation from a table by identifying initial value and multiplier.","question_html":"<section class=\"problem\" id=\"CP10A-05\"><h2>CP10A-05</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students write an exponential equation from a table by identifying the initial value and multiplier.</div>\n<p class=\"directions\">Write an equation to represent the information in the table.</p>\n<div class=\"prompt\"><table><tr><th>$x$</th><td>$0$</td><td>$1$</td><td>$2$</td><td>$3$</td></tr><tr><th>$f(x)$</th><td>$1600$</td><td>$2000$</td><td>$2500$</td><td>$3125$</td></tr></table></div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0078","original_source":"cpm-CP10A-06","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Write an exponential equation from a table by identifying initial value and multiplier.","question_html":"<section class=\"problem\" id=\"CP10A-06\"><h2>CP10A-06</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students write an exponential equation from a table whose first listed x-value is not 0.</div>\n<p class=\"directions\">Write an equation to represent the information in the table.</p>\n<div class=\"prompt\"><table><tr><th>$x$</th><td>$1$</td><td>$2$</td><td>$3$</td></tr><tr><th>$y$</th><td>$40$</td><td>$32$</td><td>$25.6$</td></tr></table></div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0079","original_source":"cpm-CP10A-07","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Write an exponential equation from a table by identifying initial value and multiplier.","question_html":"<section class=\"problem\" id=\"CP10A-07\"><h2>CP10A-07</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students write an exponential equation from a table by identifying initial value and growth factor.</div>\n<p class=\"directions\">Write an equation to represent the information in the table.</p>\n<div class=\"prompt\"><table><tr><th>$x$</th><td>$0$</td><td>$1$</td><td>$2$</td></tr><tr><th>$f(x)$</th><td>$1.8$</td><td>$5.76$</td><td>$18.432$</td></tr></table></div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0080","original_source":"cpm-CP10A-08","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"2","unit_section_title":"Unit 7, Section 2: Writing Exponential Equations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Write an exponential equation from a table by identifying initial value and multiplier.","question_html":"<section class=\"problem\" id=\"CP10A-08\"><h2>CP10A-08</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students write an exponential equation from a table by identifying initial value and multiplier.</div>\n<p class=\"directions\">Write an equation to represent the information in the table.</p>\n<div class=\"prompt\"><table><tr><th>$x$</th><td>$0$</td><td>$1$</td><td>$2$</td></tr><tr><th>$y$</th><td>$5$</td><td>$35$</td><td>$245$</td></tr></table></div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0081","original_source":"cpm-5-4","source_lesson":"Lesson 5.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Connects exponential tables to graph behavior and describes an exponential graph.","question_html":"<section class=\"problem\" id=\"5-4\"><h2>5-4</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div><div class=\"audit\">Audit note: Connects exponential tables to graph behavior and describes an exponential graph.</div><div><p class=\"\" style=\"\"> A NEW FAMILY? \t</p><p class=\"\" style=\"\">Look back at the tables you created in problems <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-1</span> and <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-3</span>.\u00a0</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">What pattern do they all have in common? \u00a0Functions that have this pattern are called<strong> exponential functions</strong>.\u00a0</p></li><li><p>Obtain the <a class=\"resource-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.1.1%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.1.1 Resource Page</a> from your teacher or use the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/bpdooyhcuo\" rel=\"noopener\" target=\"_blank\">5-4 Student eTool</a>. Click in the lower right corner of the graph to view it in full-screen mode. Graph the data for Case 2. Give a complete description of the graph.</p><div class=\"graph-workspace\"></div></li></ol></div></section>","resources":[{"label":"Lesson 5.1.1 Resource Page","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.1.1%20RP.pdf"},{"label":"5-4 Student eTool","href":"https://www.desmos.com/calculator/bpdooyhcuo"}]},{"problem_id":"unit07-0082","original_source":"cpm-5-29","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Builds a table and graph for repeated bounces; exponential decay graphing with discrete data.","question_html":"<section class=\"problem\" id=\"5-29\"><h2>5-29</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div><div class=\"audit\">Audit note: Builds a table and graph for repeated bounces, emphasizing exponential decay and discrete data.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-sm-8\"><p class=\"\" style=\"\">MODEL FOR MANY BOUNCES \t</p><p class=\"\" style=\"\">Imagine that you drop the ball you used in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-19</span> from a height of $200$ cm, but this time you let it bounce repeatedly.</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">As a team, discuss this situation.\u00a0 Then sketch a picture showing what this situation would look like.\u00a0 Your sketch should show a minimum of $6$ bounces after you release the ball.\u00a0</p></li></ol></div><div class=\"col-sm-4 col-align-top\" style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\" style=\"\">Predict your ball\u2019s rebound height after each successive bounce if its starting height is $200$ cm.\u00a0 Create a table with these predicted heights. \u00a0\u00a0\u00a0</p></li><li><p class=\"\" style=\"\">What are the independent and dependent variables in this situation? \u00a0</p></li><li><p class=\"\" style=\"\">Graph your predicted rebound heights.</p></li><li><p class=\"\" style=\"\">Should the points on your graph be connected? How can you tell?</p></li></ol></div><div class=\"graph-workspace\"></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0083","original_source":"cpm-5-116","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Uses graphing technology to solve exponential equations approximately.","question_html":"<section class=\"problem\" id=\"5-116\">\n<h2>5-116</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Uses graphing technology to solve exponential equations approximately.</div>\n<div><div class=\"row\"><div class=\"col-sm-9\"><p><strong>Additional Challenge:\u00a0\u00a0</strong>Discuss with your team how you can use your graphing calculator to solve each of the following\u00a0equations for <em>$x$</em>, accurate to the nearest $0.01$.</p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p>\u00a0$200(0.5)^x=3.125$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>\u00a0$318=6\\cdot 3^x$\u00a0</p></li></ol></div></div></div></div></div>\n</section>"},{"problem_id":"unit07-0084","original_source":"cpm-5-118","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Review/Preview","audit_status":"authoritative","notes":"Determines whether an exponential function can reach a target output and finds the input.","question_html":"<section class=\"problem\" id=\"5-118\">\n<h2>5-118</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Determines whether an exponential function can reach a target output and finds the corresponding input.</div>\n<div><p>Is it possible for the function <em>$f(x) = 5 \\cdot  2^{x}$ </em>to have an output of $200$? If so, what input gives this output? If not, justify why not.\u00a0\u00a0</p></div>\n</section>"},{"problem_id":"unit07-0085","original_source":"cpm-6-40","source_lesson":"6.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Review/Preview","audit_status":"authoritative","notes":"Interprets an exponential decay graph and its horizontal asymptote in context.","question_html":"<section class=\"problem\" id=\"6-40\">\n<h2>6-40</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Interprets an exponential decay graph and its horizontal asymptote in context.</div>\n<div><div class=\"row\"><div class=\"col-xl-9\"><p>The graph below represents the temperature of a cup of hot water that is left on a kitchen table. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>What does the horizontal line (asymptote) represent?</p></li><li><p>How would the graph be different if the cup of hot water was left outside during winter instead?</p></li></ol></div><div class=\"col-xl-3 col-align-top\"><p><strong><img alt=\"A first quadrant coordinate plane with Time labeled on the x axis and Temperature labeled on the y axis with an exponential decay graph that decreases to a line halfway up the y-axis.\" class=\"figure-img\" src=\"assets/6-40.png\"/></strong></p></div></div></div>\n</section>"},{"problem_id":"unit07-0086","original_source":"cpm-7-1","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Matches equations of the form y=b^x to increasing and decreasing exponential graph shapes.","question_html":"<section class=\"problem\" id=\"7-1\">\n<h2>7-1</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Introduces increasing and decreasing exponential graphs and matches equations of the form y=b^x to graph shapes.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\"> BEGINNING TO INVESTIGATE EXPONENTIALS</p><div class=\"row\"><div class=\"col-sm-6\"><p class=\"\" style=\"\">In Chapter 5, you graphed several exponential functions. Some graphs, like those that modeled the rabbit populations in problem 5-4, were <em>increasing</em> exponential functions and looked similar to the two exponential functions graphed at right.</p></div></div><div class=\"row\"><div class=\"col-sm-6\"><p class=\"\" style=\"\">Other graphs, such as the rebound-height graphs from the bouncing ball activity (problem 5-20), represented <em>decreasing</em> exponential functions and looked similar to the third curve, shown in bold at right.</p></div></div><p class=\"\" style=\"\">You already know that equations of the form <em>$y=mx+b$\u00a0</em>\u00a0represent the family of lines, and you know what effect changing the parameters <em>m </em>and <em>b</em> have on the graph. Today you will begin to learn more about the exponential function family. In their simplest form, the equations of exponential functions look like\u00a0$y=b^x$<em>.</em></p><p class=\"\" style=\"\">By experimenting with different values of <em>b</em>, find three equations in\u00a0$y=b^x$\u00a0 form that have graphs appearing to match the three graphs shown above.\u00a0 Confirm your results using your graphing calculator and be ready to share your results with the class.\u00a0</p><div class=\"figure-row\"><img alt=\"Exponential graphs for 7-1\" class=\"figure-img\" src=\"assets/7-1.png\"/></div></div>\n</section>"},{"problem_id":"unit07-0087","original_source":"cpm-7-2","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Investigates how base values affect the graph of y=b^x.","question_html":"<section class=\"problem\" id=\"7-2\">\n<h2>7-2</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Investigates how different base values b affect the graph of y=b^x.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\"> INVESTIGATING <em>$y=b^x$ </em>, Part One</p><p class=\"\" style=\"\">What other types of graphs exist for equation of the form <em>$y=b^x$</em>?</p><p class=\"\" style=\"\"><strong>Your Task:</strong> With your team, try different values of <em>b</em> to try to find as many different looking graphs as possible. (Stick to small values of <em>b</em>, for example, less than 10. Keep the window on your calculator set from \u201310 to 10 in both the <em>x</em> and <em>y</em> direction.)\u00a0\u00a0</p><p class=\"\" style=\"\">Decide as a team what different values of <em>b </em>to try so that you find as many different looking graphs as possible. Be sure to keep track of what you have tried with a sketch of the resulting graph so that you may refer to it later. Use the questions listed in the \u201cDiscussion Points\u201d section below to help get you started. \u00a0Investigate using the\u00a0<a class=\"etool-link\" href=\"https://www.desmos.com/calculator/ly8nwqdjfy\" rel=\"noopener\" target=\"_blank\"><em>7-2 Student eTool</em></a><a class=\"etool-link\" href=\"https://www.desmos.com/calculator/qjbedo7i8q\" rel=\"noopener\" target=\"_blank\"><em></em></a>.\u00a0Click in the lower right corner of the graph to view it in full-screen mode.</p><div class=\"figure-row\"><img alt=\"Desmos graph for 7-2\" class=\"figure-img\" src=\"assets/7-2.png\"/></div></div>\n</section>","resources":[{"label":"7-2 Student eTool","href":"https://www.desmos.com/calculator/ly8nwqdjfy"},{"label":"https://www.desmos.com/calculator/qjbedo7i8q","href":"https://www.desmos.com/calculator/qjbedo7i8q"}]},{"problem_id":"unit07-0088","original_source":"cpm-7-3","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Analyzes exponential decay graph behavior, x-intercept, and horizontal asymptote.","question_html":"<section class=\"problem\" id=\"7-3\">\n<h2>7-3</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Analyzes exponential decay, long-run behavior, intercepts, and horizontal asymptote behavior for y=(1/2)^x.</div>\n<div class=\"problem-body\"><div class=\"row\"><div class=\"col-sm-9\"><p class=\"\" style=\"\">The graph of the function <em>$y=\\left(\\frac{1}{2}\\right)^x$\u00a0</em>is shown at right.  \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Describe what happens to <em>y</em> as <em>x</em> gets bigger and bigger. For example, what is <em>y</em> when <em>$x=20$</em>, <em>$x=100$</em>, <em>$x=1000$</em>? \u00a0<em>$x=$</em>\u00a0(a much larger number)?\u00a0</p></li><li><p class=\"\" style=\"\">Does the graph of <em>$y=\\left(\\frac{1}{2}\\right)^x$<sup>\u00a0</sup></em>have an\u00a0<em>x</em>-intercept? Explain how you know. \u00a0</p></li><li><p class=\"\" style=\"\">When <em>$x$</em> is very large, the graph of\u00a0<em>$y=\\left(\\frac{1}{2}\\right)^x$</em>\u00a0approaches the <em>$x$</em>-axis. That is, as <em>$x$</em> gets larger and larger (farther to the right along the curve), the closer the curve gets to the <em>x</em>-axis. In this situation, the <em>$x$</em>-axis is called an<strong> asymptote</strong>\u00a0of\u00a0<em>$y=\\left(\\frac{1}{2}\\right)^x$</em>. You can read more about asymptotes in the Math Notes box at the end of this lesson.\u00a0 \t\t</p><p class=\"\" style=\"\">Does\u00a0<em>$y=\\left(\\frac{1}{2}\\right)^x$</em>\u00a0have a vertical asymptote? In other words, is there a vertical line that the graph above approaches? Why or why not?\u00a0\u00a0</p></li></ol></div></div><div class=\"figure-row\"><img alt=\"Graph of y=(1/2)^x for 7-3\" class=\"figure-img\" src=\"assets/7-3.png\"/></div></div>\n</section>"},{"problem_id":"unit07-0089","original_source":"cpm-7-4","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Describes key graph features of the y=b^x family using equation, table, and graph evidence.","question_html":"<section class=\"problem\" id=\"7-4\">\n<h2>7-4</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Describes and justifies key features of graphs in the y=b^x family using multiple representations.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\"> INVESTIGATING $y=b^x$, Part Two</p><p class=\"\" style=\"\">Now that you, with your class, have found all of the possible graphs for\u00a0$y=b^x$, your teacher will assign your team one or two of the types of graphs to investigate further. Completely describe the graphs. Use the \u201cDiscussion Points\u201d section below to guide your investigation of this graph. Look for ways to justify your summary statements using more than one representation (equation, table, graph).</p><p class=\"\" style=\"\">As a team, organize your graphs and summary statements into a stand-alone poster that clearly communicates what you learned about your set of graphs. Be sure to include all of your observations along with examples to demonstrate them. Anyone should be able to answer the questions below after examining your poster. Use colors, arrows, labels, and other tools to help explain your ideas.<em>\u00a0</em></p></div>\n</section>"},{"problem_id":"unit07-0090","original_source":"cpm-7-5","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Examines base restrictions and special cases for exponential graphs.","question_html":"<section class=\"problem\" id=\"7-5\">\n<h2>7-5</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Examines restrictions and special cases for the base b in exponential functions.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\"> Exponential functions have some interesting characteristics. Consider functions of the form $y=b^x$ as you discuss the questions below.  \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Exponential functions such as\u00a0$y=b^x$\u00a0are defined only for \u00a0<em>$b\u00a0&gt; 0$</em>. Why do you think this is? That is, why would you not want to use negative values of <em>$b$</em>?\u00a0\u00a0</p></li><li><p class=\"\" style=\"\">Can you consider\u00a0$y = 1^{x}$ or <em>$y = 0^{x}$</em> to be exponential functions? Why or why not? How are they different from other exponential functions?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0091","original_source":"cpm-7-6","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Learning Log","audit_status":"authoritative","notes":"Learning Log reflection on how changing b affects y=b^x graphs.","question_html":"<section class=\"problem\" id=\"7-6\">\n<h2>7-6</h2>\n<div class=\"meta\"><span class=\"pill\">Lesson</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Learning Log reflection on how changing b affects graphs of y=b^x.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\"> LEARNING LOG \t</p><div class=\"row\"><div class=\"col-sm-9\"><p class=\"\" style=\"\">Look over your work from this lesson. What questions did you ask yourself as you were making observations and statements? How does changing the value of <em>b</em> affect a graph? What questions do you still have after this investigation? Write a Learning Log entry describing what mathematical ideas you developed during this lesson. Title this entry \u201cInvestigating\u00a0<em>y</em>\u00a0=\u00a0<em>b<sup>x\u00a0</sup></em>\u201d and label it with today\u2019s date.</p></div></div></div>\n</section>"},{"problem_id":"unit07-0092","original_source":"cpm-7-14","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Review/Preview","audit_status":"authoritative","notes":"Sketches y=b^x for b>1, 0<b<1, and b=1.","question_html":"<section class=\"problem\" id=\"7-14\">\n<h2>7-14</h2>\n<div class=\"meta\"><span class=\"pill\">Review/Preview</span><span>Sorted to Unit 7, Section 3</span></div>\n<div class=\"audit\">Audit note: Sketches the general shape of y=b^x for bases greater than 1, between 0 and 1, and equal to 1.</div>\n<div class=\"problem-body\"><p class=\"\" style=\"\">Sketch the shape of the graph of the function <em>$y = b^{x}$</em> given each of the following values of <em>$b$</em>. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/crqa8zr6cc\" rel=\"noopener\" target=\"_blank\"><em></em></a>\u00a0<a class=\"etool-link\" href=\"https://www.desmos.com/calculator/hd2b7shey2\" rel=\"noopener\" target=\"_blank\"><em>7-14 HW eTool</em></a>\u00a0</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\"><em>\u00a0$b$ </em>is a number larger than $1$.</p></li><li><p class=\"\" style=\"\"><em>\u00a0$b$ </em>is a number between $0$ and $1$.</p></li><li><p class=\"\" style=\"\"><em>\u00a0$b$ </em>is equal to $1$.</p></li></ol></div>\n</section>","resources":[{"label":"https://www.desmos.com/calculator/crqa8zr6cc","href":"https://www.desmos.com/calculator/crqa8zr6cc"},{"label":"7-14 HW eTool","href":"https://www.desmos.com/calculator/hd2b7shey2"}]},{"problem_id":"unit07-0093","original_source":"cpm-7-23","source_lesson":"7.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Sketches exponential graphs directly from equations.","question_html":"<section class=\"problem\" id=\"7-23\">\n<h2>7-23</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Sketches an exponential graph directly from an equation without first making a table.</div>\n<div><p>EQUATION \u2192 GRAPH<br/> <br/> \tHow can you sketch the graph of an exponential function directly from its equation without making a table first? Discuss this with your team. Then make a reasonable sketch of the graph of $y=7(2)^x$<em></em> on your paper.</p></div>\n</section>"},{"problem_id":"unit07-0094","original_source":"cpm-7-70","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Sketches exponential graphs directly from equations.","question_html":"<section class=\"problem\" id=\"7-70\">\n<h2>7-70</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Sketches exponential graphs directly from equations by reasoning about starting value, multiplier, and shape.</div>\n<p>EQUATION \u2192 GRAPH</p>\n<p>For each equation below, make a reasonable sketch of the graph without making a table first. Discuss your strategy with your team before you begin.</p>\n<div class=\"row\">\n<div><ol class=\"lower-alpha\" type=\"a\"><li><p>$y=5(3)^x$</p></li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$y=10\\left(\\frac{1}{2}\\right)^x$</p></li></ol></div>\n<div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>$y=\\frac{1}{10}(5)^x$</p></li></ol></div>\n</div>\n</section>"},{"problem_id":"unit07-0095","original_source":"cpm-7-76","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compares discrete geometric sequences with continuous exponential functions graphically.","question_html":"<section class=\"problem\" id=\"7-76\">\n<h2>7-76</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Compares a discrete geometric sequence with its related continuous exponential function using graphs and domain.</div>\n<p>A particular sequence can be represented by <em>$t(n)=2(3)^n$</em>.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>What are <em>$t(0)$</em>, <em>$t(1)$</em>, $t(2)$, and <em>$t(3)$</em>?</p></li>\n<li><p>Graph this sequence. What is the domain?</p></li>\n<li><p>On the same set of axes, graph the function <em>$f(x)=2(3)^x$</em>.</p></li>\n<li><p>How are the two graphs similar? How are they different?</p></li>\n</ol>\n</section>"},{"problem_id":"unit07-0096","original_source":"cpm-7-85","source_lesson":"7.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Lesson","audit_status":"authoritative","notes":"Uses fractional-exponent reasoning to explain graphing limitations of negative bases in y=b^x.","question_html":"<section class=\"problem\" id=\"7-85\">\n<h2>7-85</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Uses fractional-exponent reasoning to explain why exponential graphs with negative bases are not reliable continuous exponential functions.</div>\n<div><div><div><p>Recall that when you investigated <em>$y=b^x$</em> in problem 7-2, the graphing calculator produced graphs like the one at right for negative values of <em>b</em> when you used the \u201czoom decimal\u201d option<em>.</em> Use what you have learned about the meaning of fractional exponents to explain why <em>$y=(\u22122)^x$</em> is impossible to graph accurately.</p></div><div><p><img alt=\"Captured graph model for 7-85.\" class=\"figure-img\" src=\"assets/7-85.png\"/></p></div></div></div>\n</section>"},{"problem_id":"unit07-0097","original_source":"cpm-7-99","source_lesson":"7.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Review/Preview","audit_status":"authoritative","notes":"Evaluates exponential functions, interprets intercepts, and reasons about graph features.","question_html":"<section class=\"problem\" id=\"7-99\">\n<h2>7-99</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 3: Graphing Exponentials</div>\n<div class=\"audit\">Audit note: Evaluates an exponential function and reasons about intercepts and products of functions.</div>\n<div><p>If <em>$f(x)=3(2)^x$</em>, find the value of the expressions in parts (a) through (c) below. Then complete parts (d) through (f). <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/ufwm13vqls\" rel=\"noopener\" target=\"_blank\">7-99 HW eTool</a></p>\n<div class=\"row\"><div><ol class=\"lower-alpha\" type=\"a\"><li><p>$f(-1)$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$f(0)$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>$f(1)$</p></li></ol></div></div>\n<ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>What value of <em>$x$</em> gives <em>$f(x) = 12$</em>?</p></li><li><p>Where does the graph of this function cross the <em>$x$</em>-axis? The <em>$y$</em>-axis?</p></li><li><p>If <em>$g(x)=\\frac{1}{3x}$</em>, find <em>$f(x) \\cdot g(x)$</em>.</p></li></ol></div>\n</section>","resources":[{"label":"7-99 HW eTool","href":"https://www.desmos.com/calculator/ufwm13vqls"}]},{"problem_id":"unit07-0098","original_source":"cpm-CP10A-01","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Checkpoint","audit_status":"authoritative","notes":"Given an exponential equation; make a table and graph the function.","question_html":"<section class=\"problem\" id=\"CP10A-01\"><h2>CP10A-01</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students make a table of values and graph an exponential decay function from an equation.</div>\n<p class=\"directions\">Make a table of values and draw a graph of the exponential function.</p>\n<div class=\"prompt\">$y=4(0.5)^x$</div>\n<div class=\"workspace large\"></div>\n</section>"},{"problem_id":"unit07-0099","original_source":"cpm-CP10A-02","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Checkpoint","audit_status":"authoritative","notes":"Given an exponential equation; make a table and graph the function.","question_html":"<section class=\"problem\" id=\"CP10A-02\"><h2>CP10A-02</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students make a table of values and graph an exponential growth function from an equation.</div>\n<p class=\"directions\">Make a table of values and draw a graph of the exponential function.</p>\n<div class=\"prompt\">$y=2(3)^x$</div>\n<div class=\"workspace large\"></div>\n</section>"},{"problem_id":"unit07-0100","original_source":"cpm-CP10A-03","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Checkpoint","audit_status":"authoritative","notes":"Given an exponential equation; make a table and graph the function.","question_html":"<section class=\"problem\" id=\"CP10A-03\"><h2>CP10A-03</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students make a table of values and graph an exponential growth function from an equation.</div>\n<p class=\"directions\">Make a table of values and draw a graph of the exponential function.</p>\n<div class=\"prompt\">$f(x)=5(1.2)^x$</div>\n<div class=\"workspace large\"></div>\n</section>"},{"problem_id":"unit07-0101","original_source":"cpm-CP10A-04","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"3","unit_section_title":"Unit 7, Section 3: Graphing Exponentials","source_type":"Checkpoint","audit_status":"authoritative","notes":"Given an exponential equation; make a table and graph the function.","question_html":"<section class=\"problem\" id=\"CP10A-04\"><h2>CP10A-04</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students make a table of values and graph an exponential decay function from an equation.</div>\n<p class=\"directions\">Make a table of values and draw a graph of the exponential function.</p>\n<div class=\"prompt\">$f(x)=10\\left(\\frac{2}{3}\\right)^x$</div>\n<div class=\"workspace large\"></div>\n</section>"},{"problem_id":"unit07-0102","original_source":"cpm-5-31","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Compares linear rebound-height modeling to exponential successive-bounce modeling.","question_html":"<section class=\"problem\" id=\"5-31\"><h2>5-31</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div><div class=\"audit\">Audit note: Compares linear rebound-height modeling to exponential successive-bounce modeling.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\">Compare your graph for the height of successive bounces in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-29</span> to the graph for drop height versus bounce height that you investigated in Lesson <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5.1.2</span>. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Can you use the same kind of equation to model the two situations? That is, what family of functions do you think would make the best fit for each data set? Discuss this with your team and be ready to report and justify your choice.</p></li><li><p class=\"\" style=\"\">Describe how the pattern of growth for successive bounces is the same as or different from other models that you have looked at previously.</p></li></ol></div><div class=\"graph-workspace\"></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0103","original_source":"cpm-5-33","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Explains why linear and exponential models are appropriate for different rebound questions.","question_html":"<section class=\"problem\" id=\"5-33\"><h2>5-33</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div><div class=\"audit\">Audit note: Explains why linear and exponential models are each appropriate for different rebound questions.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\">Notice that your investigations of rebound patterns in Lessons <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5.1.2</span> and <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5.1.3</span> involved both a linear and an exponential model.\u00a0 Look back over your work and discuss with your team why each model was appropriate for its specific purpose.\u00a0 Be prepared to share your ideas with the class.\u00a0\u00a0</p></div>\n</section>"},{"problem_id":"unit07-0104","original_source":"cpm-5-41","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Sorts arithmetic, geometric, quadratic, Fibonacci, and other sequences using multiple representations.","question_html":"<section class=\"problem\" id=\"5-41\">\n<h2>5-41</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div><div class=\"audit\">Audit note: Sorts arithmetic, geometric, quadratic, Fibonacci, and other sequences using tables, graphs, and generators.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\"> SEQUENCE FAMILIES<br/> \tSamantha and her teacher have been busy creating new sequence generators and the sequences they produce. Below are the sequences Samantha and her teacher created.</p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">\u00a0$-4,-1,2,5,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\">\u00a0$1.5,3,6,12,\\dots$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p class=\"\">\u00a0$0,1,4,9,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p class=\"\">\u00a0$2,3.5,5,6.5,\\dots$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"5\" type=\"a\"><li><p class=\"\">\u00a0$1,1,2,3,5,8,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"6\" type=\"a\"><li><p class=\"\">\u00a0$9,7,5,3,\\dots$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"7\" type=\"a\"><li><p class=\"\">\u00a0$48,24,12,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"8\" type=\"a\"><li><p class=\"\">\u00a0$27,9,3,1,\\dots$\u00a0</p></li></ol></div></div><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"9\" type=\"a\"><li><p class=\"\">\u00a0$8,2,0,2,8,18,\\dots$\u00a0</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"10\" type=\"a\"><li><p class=\"\">\u00a0$\\frac{5}{4},\\frac{5}{2},5,10,\\dots$\u00a0</p></li></ol></div></div><p class=\"\"> \tYour teacher will give your team a set of <a class=\"resource-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1A%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.2.1A Resource Pages</a> with the above sequences on strips so that everyone in your team can see and work with them in the middle of your workspace.</p><p class=\"\"><br/> <strong>Your Task:</strong> Working together, organize the sequences into families of similar sequences. Your team will need to decide how many families to make, what common features make the sequences a family, and what characteristics make each family different from the others. Follow the directions below. As you work, use the following questions to help guide your team's discussion.</p><h3><em>Discussion Points</em></h3><p class=\"\">How can we describe the pattern?</p><p class=\"\">How does it grow?</p><p class=\"\">What do they have in common?</p><p class=\"\">(1) \u00a0As a team, initially sort the sequence strips into groups based on your first glance at the sequences.\u00a0 Remember that you can sort the sequences into more than two families.\u00a0 You will have a chance to revise your groups throughout this activity, so just sort them in a way that makes sense to start out with.\u00a0 Which seem to behave similarly?\u00a0 Record your groupings and what they have in common before proceeding. \u00a0<br/> \t(2) \u00a0If one exists, find a sequence generator (growth pattern) for each sequence and write it on the strip. You can express the sequence generator either in symbols or in words. Also record the next three terms in each sequence on the strips. Do your sequence families still make sense? If so, what new information do you have about your sequence families? If not, reorganize the strips and explain how you decided to group them.</p><div class=\"row\"><div class=\"col-sm-9\"><p class=\"\">(3) \u00a0Get a set of <a class=\"resource-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1B%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.2.1B Resource Pages</a> saving a copy of each of the tables and graphs for your team. Then record each sequence in a table. Your table should compare the<strong> term number</strong>, <em>$n$</em>, to the value of each<strong> term</strong>, <em>$t(n)$</em>. This means that your sequence itself is a list of <em>outputs</em> of the relationship and the <em>inputs</em> are a list of integers! The first term in a sequence is always <em>$n=1$</em>. Attach the table to the sequence strip it represents. Do your sequence families still make sense? Record any new information or reorganize your sequence families if necessary.</p><p class=\"\">(4) Now graph each sequence on a <a class=\"resource-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1C%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.2.1C Resource Page</a> or on the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/nxaibaykko\" rel=\"noopener\" target=\"_blank\">5-41 Student eTool</a>.\u00a0 Click in the lower right corner of the graph to view it in full-screen mode. Include as many terms as will fit on the existing set of axes. \u00a0Be sure to decide whether your graphs should be discrete or continuous. Use color to show the growth between the points on each graph. Attach the graph to the sequence strip it represents. Do your sequence families still make sense? Record any new information and reorganize your sequence families if necessary.\u00a0</p></div></div></div>\n</section>","resources":[{"label":"Lesson 5.2.1A Resource Pages","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1A%20RP.pdf"},{"label":"Lesson 5.2.1B Resource Pages","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1B%20RP.pdf"},{"label":"Lesson 5.2.1C Resource Page","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.2.1C%20RP.pdf"},{"label":"5-41 Student eTool","href":"https://www.desmos.com/calculator/nxaibaykko"}]},{"problem_id":"unit07-0105","original_source":"cpm-5-42","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Summarizes and justifies a sequence family using multiple representations.","question_html":"<section class=\"problem\" id=\"5-42\">\n<h2>5-42</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div><div class=\"audit\">Audit note: Requires students to summarize and justify a sequence family using multiple representations.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Choose one of the families of sequences you created in problem 5-41.\u00a0 With your team, write clear summary statements about this family of sequences.\u00a0 Refer to the Discussion Points in problem 5-41 to help you write summary statements.\u00a0 Be sure to use multiple representations to justify each statement.\u00a0 Be prepared to share your summary statements with the class.</p></div>\n</section>"},{"problem_id":"unit07-0106","original_source":"cpm-5-48","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compares quadratic-looking sequences and Fibonacci-type growth with other sequence families.","question_html":"<section class=\"problem\" id=\"5-48\">\n<h2>5-48</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 4: Comparing Function Families</div><div class=\"audit\">Audit note: Compares quadratic-looking sequences and Fibonacci-type growth with other sequence families.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Refer to sequences (c) and (i) in problem 5-41. </p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">How are these two sequences similar?</p></li><li><p class=\"\">The numbers in the sequence in part (e) from problem 5-41 are called Fibonacci numbers. They are named after an Italian mathematician who discovered the sequence while studying how fast rabbits could breed. What is different about this sequence than the other three you discovered?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0107","original_source":"cpm-5-82","source_lesson":"Lesson 5.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Compares linear, quadratic, and exponential growth patterns using tables and graphs.","question_html":"<section class=\"problem\" id=\"5-82\">\n<h2>5-82</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div>\n<div class=\"audit\">Audit note: Compares linear, quadratic, and exponential growth patterns using tables and graphs.</div>\n<div><p>\u00a0PATTERNS OF GROWTH</p><div class=\"row\"><div class=\"col-sm-4\"><p>Sequence A</p><table><tbody><tr><th><p><em>n</em></p></th><th><p><em>t</em>(<em>n</em>)</p></th></tr><tr><td><p>1</p></td><td><p>27</p></td></tr><tr><td><p>2</p></td><td><p>54</p></td></tr><tr><td><p>3</p></td><td><p>81</p></td></tr><tr><td><p>4</p></td><td><p>108</p></td></tr></tbody></table></div><div class=\"col-sm-4\"><p>Sequence B</p><table><tbody><tr><th><p><em>n</em></p></th><th><p><em>t</em>(<em>n</em>)</p></th></tr><tr><td><p>1</p></td><td><p>9</p></td></tr><tr><td><p>2</p></td><td><p>36</p></td></tr><tr><td><p>3</p></td><td><p>81</p></td></tr><tr><td><p>4</p></td><td><p>144</p></td></tr></tbody></table></div><div class=\"col-sm-4\"><p>Sequence C</p><table><tbody><tr><th><p><em>n</em></p></th><th><p><em>t</em>(<em>n</em>)</p></th></tr><tr><td><p>1</p></td><td><p>6</p></td></tr><tr><td><p>2</p></td><td><p>12</p></td></tr><tr><td><p>3</p></td><td><p>24</p></td></tr><tr><td><p>4</p></td><td><p>48</p></td></tr></tbody></table></div></div><p><strong>Your Task:</strong> </p><ul><li><p>Represent these three sequences on a graph (the <a class=\"etool-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.3.1A%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.3.1A Resource Page</a> or the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/bz8qk3gjsg\" rel=\"noopener\" target=\"_blank\">5-82 Student eTool</a>).\u00a0Click in the lower right corner of the graph to view it in full-screen mode. Use a different color for each sequence.\u00a0 Although the graph is discrete, connect the points so you can see the patterns more easily.</p></li><li><p>Consider the \"Discussion Points\" below for each sequence as you investigate the growth of these three sequences.\u00a0 You can discuss the sequences in any order.</p></li><li><p>Be prepared to share your results with the class. \t\t</p><div><p>Embedded table from the student eTool:</p><table><tr><th>n</th><th>A n</th><th>B n</th><th>C n</th></tr><tr><td>1</td><td></td><td></td><td></td></tr><tr><td>2</td><td></td><td></td><td></td></tr><tr><td>3</td><td></td><td></td><td></td></tr><tr><td>4</td><td></td><td></td><td></td></tr></table></div></li></ul></div>\n</section>","resources":[{"label":"Lesson 5.3.1A Resource Page","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.3.1A%20RP.pdf"},{"label":"5-82 Student eTool","href":"https://www.desmos.com/calculator/bz8qk3gjsg"}]},{"problem_id":"unit07-0108","original_source":"cpm-5-83","source_lesson":"Lesson 5.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Compares long-term growth behavior of linear, quadratic, and exponential sequences.","question_html":"<section class=\"problem\" id=\"5-83\">\n<h2>5-83</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div>\n<div class=\"audit\">Audit note: Uses tables/graphs to compare long-term growth of linear, quadratic, and exponential sequences.</div>\n<div><div class=\"row\"><div class=\"col-sm-9\"><p>GROWTH RATES IN SEQUENCES</p><p>Consider how fast each of the sequences is growing by looking at the tables and the graph.\u00a0 Do not make any additional computations.\u00a0 Instead make conjectures based on the tables and graphs.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>If <em>$n$</em> represents the number of years, and <em>t</em>(<em>n</em>) represents the amount of money in your savings account, which account would you want, Sequence A, B, or C?</p></li><li><p>Would your answer change if you kept the account for many years?</p></li><li><p>Obtain the <a class=\"etool-link\" href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.3.1B%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 5.3.1B Resource Page</a> from your teacher or use <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/weihbh8uet\" rel=\"noopener\" target=\"_blank\">5-83 Student eTool</a>.\u00a0Click in the lower right corner of the graph to view it in full-screen mode. Extend the tables and the graph to <em>$n = 7$</em>.\u00a0 The table for Sequence B has been completed for you.</p><div><p>Embedded table from the student eTool:</p><table><tr><th>n</th><th>A {tn}</th><th>B {tn}</th><th>C {tn}</th></tr><tr><td>1</td><td>27</td><td>9</td><td>6</td></tr><tr><td>2</td><td>54</td><td>36</td><td>12</td></tr><tr><td>3</td><td>81</td><td>81</td><td>24</td></tr><tr><td>4</td><td>108</td><td>144</td><td>48</td></tr><tr><td>5</td><td></td><td>225</td><td></td></tr><tr><td>6</td><td></td><td>324</td><td></td></tr><tr><td>7</td><td></td><td>441</td><td></td></tr></table></div></li><li><p>Based on your new graph, do you want to change your answer to part (b)?\u00a0 Why or why not?</p></li></ol></div></div></div>\n</section>","resources":[{"label":"Lesson 5.3.1B Resource Page","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_05/CCA%20Lesson%205.3.1B%20RP.pdf"},{"label":"5-83 Student eTool","href":"https://www.desmos.com/calculator/weihbh8uet"}]},{"problem_id":"unit07-0109","original_source":"cpm-5-84","source_lesson":"Lesson 5.3.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Explains why exponential growth eventually exceeds linear growth and compares quadratic growth to exponential growth.","question_html":"<section class=\"problem\" id=\"5-84\">\n<h2>5-84</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div>\n<div class=\"audit\">Audit note: Explains why exponential growth eventually exceeds linear growth and compares quadratic growth to exponential growth.</div>\n<div><p>\u00a0WHICH GROWS THE MOST?</p><ol><li><p>Will an exponentially growing bank account eventually contain more money than a linearly growing bank account for the same amount of initial savings, no matter how fast (steep) the rate of growth of the linear account?\u00a0 Use the slope triangles on your graph from problem 5-83 to help you explain.</p></li><li><p>How does the growth of a quadratic sequence like Sequence B compare to exponential growth?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0110","original_source":"cpm-5-112","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Lesson","audit_status":"authoritative","notes":"Compares an exponential sequence with the corresponding exponential function; discrete vs continuous behavior.","question_html":"<section class=\"problem\" id=\"5-112\">\n<h2>5-112</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 4: Comparing Function Families</div>\n<div class=\"audit\">Audit note: Compares an exponential sequence with the corresponding exponential function and reasons about discrete versus continuous inputs.</div>\n<div><p> Let us consider the difference between <em>$t(n)=2\\cdot 3^n$ </em>and <em>$f(x)=2\\cdot 3^x$</em>. \t</p><ol class=\"lower-alpha\"><li><p>Is\u00a0<em>$f(x)=2\\cdot 3^x$</em>\u00a0a function?\u00a0 Why or why not?\u00a0 Is \u00a0<em>$t(n)=2\\cdot 3^n$</em>\u00a0a function?</p></li><li><p>Is it possible for <em>$t(n)$</em> to equal $1400$? If so, find the value of <em>n </em>that makes <em>$t(n)=1400$</em>. If not, justify\u00a0why not.</p></li><li><p>Is it possible for <em>$f(x)$</em> to equal $1400$? If so, find the value of <em>x </em>that makes <em>$f(x)=1400$</em>. Be prepared to share your solving strategy with the class.</p></li><li><p>How are the two functions similar? How are they different?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0111","original_source":"cpm-6-9","source_lesson":"6.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"4","unit_section_title":"Unit 7, Section 4: Comparing Function Families","source_type":"Review/Preview","audit_status":"authoritative","notes":"Finds missing terms in arithmetic and geometric sequence tables, connecting linear and multiplicative growth patterns.","question_html":"<section class=\"problem\" id=\"6-9\">\n<h2>6-9</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 4: Comparing Function Families</div>\n<div class=\"audit\">Audit note: Finds missing terms in arithmetic and geometric sequence tables, connecting linear and multiplicative growth patterns.</div>\n<div><p>Find the missing term in each sequence. </p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><table><tbody><tr><th><p><em>$n$</em></p></th><th><p><em>$t\\left(n\\right)$</em></p></th></tr><tr><td><p>$1$</p></td><td><p>$1$</p></td></tr><tr><td><p>$5$</p></td><td><p>$-7$</p></td></tr><tr><td><p>$10$</p></td><td><p>$-17$</p></td></tr><tr><td><p>$23$</p></td><td></td></tr></tbody></table></li></ol><p>\u00a0Hint: This is an arithmetic sequence.</p></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><table><tbody><tr><th><p><em>$n$</em></p></th><th><p><em>$t\\left(n\\right)$</em></p></th></tr><tr><td><p>$1$</p></td><td><p>$10$</p></td></tr><tr><td><p>$2$</p></td><td><p>$18$</p></td></tr><tr><td><p>$3$</p></td><td><p>$32.4$</p></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0112","original_source":"cpm-5-28","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses rebound ratio as a multiplicative model for prediction in context.","question_html":"<section class=\"problem\" id=\"5-28\"><h2>5-28</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Uses a rebound ratio as a constant multiplier to predict rebound height in context.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\"> Consider the work you did in Lesson <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5.1.2</span>, in which you found a rebound ratio.  \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">What was the rebound ratio for the ball your team used?</p></li><li><p class=\"\" style=\"\">Did the height you dropped the ball from affect this ratio?</p></li><li><p class=\"\" style=\"\">If you were to use the same ball again and drop it from <em>any</em> height, could you predict its rebound height? Explain how you would do this.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0113","original_source":"cpm-5-30","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Collects and compares experimental many-bounce data to an exponential decay model.","question_html":"<section class=\"problem\" id=\"5-30\"><h2>5-30</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Collects experimental many-bounce data and tests an exponential decay model against predictions.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-sm-8\"><p class=\"\" style=\"\">TESTING THE MANY-BOUNCE MODEL \t</p><p class=\"\" style=\"\">Now you will test the accuracy of the predictions you made in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-29</span>.\u00a0<br/> </p><p class=\"\" style=\"\"><strong>Your Task:</strong> Test your predictions by collecting experimental data. Use the same team roles as you used in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-19</span>. Drop your ball, starting from an initial height of $200$ cm, and record your data in a table. Then compare your experimental data to your predictions using your table and your graph. How do they compare? What might cause your experimental data to be different from your predictions? Do you think that your table and graph model the situation appropriately? Why or why not?</p></div><div class=\"col-sm-4 col-align-top\" style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div><ul class=\"bullet\"><li><p class=\"\" style=\"\">These suggestions will help you gather accurate data: \t</p></li><li><p class=\"\" style=\"\">Have a spotter catch the ball just as it reaches the top of its first rebound and have the spotter \u201cfreeze\u201d the ball in place.</p></li><li><p class=\"\" style=\"\">Record the first rebound height and then drop the ball again from that new height.</p></li><li><p class=\"\" style=\"\">Catch and \u201cfreeze\u201d it again at the second rebound height.</p></li><li><p class=\"\" style=\"\">Repeat this process until you have collected at least six data points (or until the height of the bounce is so small that it is not reasonable to continue).</p></li></ul></div><div class=\"graph-workspace\"></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0114","original_source":"cpm-5-32","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses an exponential decay model for long-term rebound-height prediction and interpretation.","question_html":"<section class=\"problem\" id=\"5-32\"><h2>5-32</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Uses an exponential decay model to predict long-term rebound height and interpret behavior.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\"> \t\t\t If you continued to let your ball bounce uninterrupted, how high would the ball be after $12$ bounces? Would the ball ever stop bouncing? Explain your answer in terms of both your experimental data and your equation.</p></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0115","original_source":"cpm-5-34","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Computes rebound ratio and uses it for repeated-bounce exponential predictions.","question_html":"<section class=\"problem\" id=\"5-34\"><h2>5-34</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Computes a rebound ratio and uses it to make first-bounce and repeated-bounce predictions.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\">DeShawna and her team gathered data for their ball and recorded it in the table shown below.\u00a0\u00a0</p><table style=\"margin: 0 auto;\"><tbody><tr><th data-colwidth=\"100\" style=\"text-align:center;vertical-align:middle;width:100px;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"\">Drop Height</p></th><th data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">Rebound<br/> Height</p></th></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$150$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$124$ cm</p></td></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$70$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$59$ cm</p></td></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$120$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$100$ cm</p></td></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$100$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$83$ cm</p></td></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$110$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;border-bottom:1px solid black;\"><p class=\"\" style=\"text-align: center\">$92$ cm</p></td></tr><tr><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-top:1px solid black;border-right:1px solid black;\"><p class=\"\" style=\"text-align: center\">$40$ cm</p></td><td data-colwidth=\"100\" style=\"text-align:center;width:100px;border-left:1px solid black;border-top:1px solid black;\"><p class=\"\" style=\"text-align: center\">$33$ cm</p></td></tr></tbody></table><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">What is the rebound ratio for their ball?</p></li></ol><ul class=\"plain\"><li></li></ul><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\" style=\"\">Predict how high DeShawna\u2019s ball will rebound if it is dropped from $275$ cm. Look at the precision of DeShawna\u2019s measurements in the table. Round your calculation to a reasonable number of decimal places.</p></li><li><p class=\"\" style=\"\">Suppose the ball is dropped and you notice that its rebound height is $60$ cm. From what height was the ball dropped? Use an appropriate precision for your answer.</p></li></ol><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p class=\"\" style=\"\">Suppose the ball is dropped from a window $200$ meters up the Empire State Building. What would you predict the rebound height to be after the first bounce?</p></li><li><p class=\"\" style=\"\">How high would the ball in part (d) rebound after the second bounce? After the third bounce?</p></li></ol><ul class=\"plain\"><li></li></ul></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0116","original_source":"cpm-5-35","source_lesson":"Lesson 5.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Applies exponential decay repeatedly to predict rebound heights.","question_html":"<section class=\"problem\" id=\"5-35\"><h2>5-35</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Applies exponential decay repeatedly to predict rebound heights after multiple bounces.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\" style=\"\">Look back at the data given in problem <span class=\"bookSpecificContent\" data-book-id=\"77c6bab0-733e-11e9-be9b-611c324990be\">5-18</span> that describes the rebound ratio for an official tennis ball. Suppose you drop such a tennis ball from an initial height of $10$ feet. </p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">How high would it rebound after the first bounce?</p></li><li><p class=\"\" style=\"\">How high would it rebound after the second bounce?</p></li><li><p class=\"\" style=\"\">How high would it rebound after the fifth bounce?</p></li></ol><ul class=\"plain\"><li></li></ul></div><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit07-0117","original_source":"cpm-5-52","source_lesson":"Lesson 5.2.1","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Models repeated halving as exponential decay and predicts future amounts.","question_html":"<section class=\"problem\" id=\"5-52\">\n<h2>5-52</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div><div class=\"audit\">Audit note: Models repeated halving as exponential decay and predicts future amounts.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">A tank contains $8000$ liters of water. Each day, half of the water in the tank is removed. How much water will be in the tank at the end of:\u00a0\u00a0</p><div class=\"row\"><div class=\"col-sm-6\"><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">The $4^{\\text{th}}$ day?</p></li></ol></div><div class=\"col-sm-6\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\">The $8^{\\text{th}}$ day?</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0118","original_source":"cpm-5-95","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses exponential models, tables, graphs, intersections, and predictions in context.","question_html":"<section class=\"problem\" id=\"5-95\">\n<h2>5-95</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses exponential models, tables, graphs, and intersections to answer contextual modeling questions.</div>\n<div><div class=\"row\"><div class=\"col-sm-9\"><p>MULTIPLE REPRESENTATIONS ON THE GRAPHING CALCULATOR \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>According to the model in problem 5-93, how many weeks will it take for the weekly sales to drop to only one <em>$\\pi$</em>Roid per week?  Make a conjecture.</p></li><li><p>Before calculating the exact answer to the question in part (a), become comfortable with using your graphing calculator.  On your calculator, make a graph for the sales of <em>$\\pi$</em>Phones (problem 5-91) for the first year.  Sketch the graph on your paper.  Make sure you show the scale of the axes on your sketch.</p></li><li><p>Use the table on your calculator to determine where, if at all, the graph in part (b) crosses the <em>x</em>-axis.</p></li></ol><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>Enter the explicit equations for both problems 5-91, <em>$t\\left(n\\right) = 100 \\cdot  1.15^{n}$</em>, and 5-92, <em>$t\\left(n\\right) = 10{,}000 \\cdot  1.07^{n}$</em>, in your calculator.  Use your table to find the number of weeks it takes for sales in the first equation to exceed the sales in the second equation.</p></li><li><p>Make a sketch of the graph of both equations in part (d).  Be sure to show the point of intersection.  Label the scale on both axes.</p></li><li><p>Now use your calculator to answer the question in part (a).  How close was your conjecture?</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit07-0119","original_source":"cpm-5-97","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Introduces percent discount and tax as multipliers in a contextual model.","question_html":"<section class=\"problem\" id=\"5-97\">\n<h2>5-97</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Introduces percent discount and tax as multipliers in a contextual model.</div>\n<div><p> PERCENTS AS MULTIPLIERS</p><p>What a deal!  Just deShirts is having a $20\\%$ off sale.  Trixie rushes to the store and buys $14$ shirts.  When the clerk rings up her purchases, Trixie sees that the clerk has added the $5\\%$ sales tax first, before taking the discount.  Trixie wonders whether adding the sales tax before the discount makes her final cost more than adding the sales tax after the discount.  Without making any calculations, make a conjecture.  Is Trixie getting charged more when the clerk adds sales tax first?  The next few problems will help you figure it out for sure. </p></div>\n</section>"},{"problem_id":"unit07-0120","original_source":"cpm-5-98","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses area models to reason about repeated percent discounts and order of operations with multipliers.","question_html":"<section class=\"problem\" id=\"5-98\">\n<h2>5-98</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses area models to reason about repeated percent discounts and order of operations with multipliers.</div>\n<div><p> Karen works for a department store and receives a $20\\%$ discount on any purchases that she makes. The department store is having a clearance sale, and every item will be marked $30\\%$ off the regular price. Karen has decided to buy the $$100 dress she\u2019s been wanting. When she includes her employee discount with the sale discount, what is the total discount she will receive? Does it matter what discount she takes first? Use the questions below to help you answer this question. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Use the grids like the ones below to picture another way to think about this situation. Using graph paper, create two $10$-by-$10$ grids (as shown below) to represent the $$100 price of the dress.</p></li></ol><div class=\"row\"><div class=\"col-sm-6\"><p><strong>     CASE 1:</strong> $20\\%$ discount first<br/> </p></div><div class=\"col-sm-6\"><p><strong>CASE 2:</strong> $30\\%$ discount first<br/> </p></div></div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>Use the first grid to represent the $20\\%$ discount followed by the $30\\%$ discount (Case 1). Use one color to shade the number of squares that represent the first $20\\%$ discount. For whatever is left (unshaded), find the $30\\%$ discount and use another color to shade the corresponding number of squares to represent this second discount. Then repeat the process (using the other grid) for the discounts in reverse order (Case 2).</p></li><li><p>How many squares remain after the first discount in Case 1? In Case 2?</p></li><li><p>How many squares remain after the second discount in Case 1? In Case 2?</p></li><li><p>Explain why these results make sense.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0121","original_source":"cpm-5-99","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Represents tax and discount algebraically and justifies multiplier order.","question_html":"<section class=\"problem\" id=\"5-99\">\n<h2>5-99</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Represents tax and discount algebraically and justifies why multiplication order does not change final cost.</div>\n<div><p> Suppose that Trixie\u2019s shirts cost <em>x</em> dollars in problem 5-97. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>If <em>$x$</em> represents the cost, how could you represent the tax? How could you represent the cost plus the tax?</p></li><li><p>How could you represent the discount? How could you represent the cost of the shirt after the discount?</p></li><li><p>Did Trixie get charged more because the clerk added the sales tax first?  Justify your reasoning.</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0122","original_source":"cpm-5-100","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Models exponential growth and decay in a rabbit population context.","question_html":"<section class=\"problem\" id=\"5-100\">\n<h2>5-100</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models exponential growth and decay in a rabbit population context.</div>\n<div><p>Remember the \u201cMultiplying Like Bunnies\u201d problem at the beginning of this chapter?  In that problem, Lennie and George started with $2$ rabbits and each month the number of rabbits that they had doubled since each pair of rabbits produced another pair of rabbits. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Find an equation for this situation.  Let <em>$y$ </em>represent the number of rabbits after <em>$x$</em> months.</p></li><li><p>Lennie and George now have over $30$ million rabbits.  How many months have passed?</p></li><li><p>With $30$ million rabbits, the bunny farm is getting overcrowded and some of the rabbits are dying from a contagious disease.  The rabbits have stopped reproducing, and the disease is reducing the total rabbit population at a rate of about $30\\%$ each month.  If this continues, then in how many months will the population drop below $100$ rabbits?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0123","original_source":"cpm-5-103","source_lesson":"Lesson 5.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses multiple representations to analyze repeated-halving exponential decay.","question_html":"<section class=\"problem\" id=\"5-103\">\n<h2>5-103</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses multiple representations to analyze a repeated-halving exponential decay situation.</div>\n<div><p>Mr. C is such a mean teacher! The next time Mathias gets in trouble, Mr. C has designed a special detention for him. Mathias will have to go out into the hall and stand exactly $100$ meters away from the exit door and pause for a minute. Then he is allowed to walk exactly halfway to the door and pause for another minute. Then he can again walk exactly half the remaining distance to the door and pause again, and so on. Mr. C says that when Mathias reaches the door he can leave, <em>unless</em> he breaks the rules and goes more than halfway, even by a tiny amount. When can Mathias leave? Prove your answer using multiple representations. </p></div>\n</section>"},{"problem_id":"unit07-0124","original_source":"cpm-5-121","source_lesson":"Lesson 5.3.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes equations for exponential growth and decay situations involving depreciation and population growth.","question_html":"<section class=\"problem\" id=\"5-121\">\n<h2>5-121</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Writes equations for exponential growth and decay situations involving depreciation and population growth.</div>\n<div><p>Write equations to solve each of the following problems. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>When the Gleo Retro (a trendy commuter car) is brand new, it costs $$23,500. Each year it loses $15\\%$ of its value. What will the car be worth when it is $15$ years old?</p></li><li><p>Each year the population of Algeland increases by $12\\%$. The population is currently $14{,}365{,}112$. What will the population be $20$ years from now?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0125","original_source":"cpm-6-107","source_lesson":"6.2.5","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Compares linear and exponential models for decay data using scatterplots, regressions, and residual plots.","question_html":"<section class=\"problem\" id=\"6-107\">\n<h2>6-107</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Compares linear and exponential models for decay data using scatterplots, regressions, and residual plots.</div>\n<div><div><div class=\"row\"><div class=\"col-sm-9\"><p>Recall that Giulia\u2019s father uses dry ice to keep the glasses in his restaurant very cold. The dry ice sublimates in the restaurant cooler as shown in the table at right. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>Recreate the scatterplot and the LSRL of this data on your calculator or use the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/lrfvn1zcco\" rel=\"noopener\" target=\"_blank\">6-107 Student eTool</a>. Click in the lower right corner of the graph to view it in full-screen mode.Sketch the residual plot.  What does the residual plot tell you about the original data Giulia collected? \t\t</p></li><li><p>What type of function might fit this data better?   </p></li></ol></div><div class=\"col-sm-3\"><table><tbody><tr><th><p># hours<br/> \t\t\t\tafter<br/> \t\t\t\tnoon</p></th><th><p>Weight<br/> \t\t\t\tof dry<br/> \t\t\t\tice (oz)</p></th></tr><tr><td><p>$0$</p></td><td><p>$15.3$</p></td></tr><tr><td><p>$1$</p></td><td><p>$14.7$</p></td></tr><tr><td><p>$2$</p></td><td><p>$14.3$</p></td></tr><tr><td><p>$3$</p></td><td><p>$13.6$</p></td></tr><tr><td><p>$4$</p></td><td><p>$13.1$</p></td></tr><tr><td><p>$5$</p></td><td><p>$12.5$</p></td></tr><tr><td><p>$6$</p></td><td><p>$11.9$</p></td></tr><tr><td><p>$7$</p></td><td><p>$11.5$</p></td></tr><tr><td><p>$8$</p></td><td><p>$11.0$</p></td></tr><tr><td><p>$9$</p></td><td><p>$10.6$</p></td></tr><tr><td><p>$10$</p></td><td><p>$10.2$</p></td></tr></tbody></table></div></div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>Use your calculator to find the exponential regression equation. Add this graph to the scatterplot sketch. Be sure to label the graph with the equation.  </p></li></ol><div class=\"row\"><div class=\"col-sm-9\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>Based on the scatterplot alone, does the linear model or the exponential model fit the data better?</p></li><li><p>Make a residual plot of the exponential regression. Comment on the appropriateness of the exponential model.</p></li></ol></div><div class=\"col-sm-3 col-align-top\"><p></p></div></div></div><p><img alt=\"Figure for 6-107\" class=\"figure-img\" src=\"assets/6-107.png\"/></p></div>\n</section>","resources":[{"label":"6-107 Student eTool","href":"https://www.desmos.com/calculator/lrfvn1zcco"}]},{"problem_id":"unit07-0126","original_source":"cpm-CL6-129","source_lesson":"Chapter 6 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"Percent growth, multiplier, prediction, and contextual exponential model.","question_html":"<div class=\"card problem\" id=\"CL6-129\">\n<div class=\"problem-title\">CL 6-129</div>\n<p>In 2012 the average cost for a new, midsized car was about $\\$31{,}000$. New car prices tend to go up about $2\\%$ every year.</p>\n<ol class=\"lower-alpha\">\n<li>What is the multiplier for this situation?</li>\n<li>If this trend continues, what will be the cost in $4$ years?</li>\n<li>Write an equation that represents the cost in $n$ years.</li>\n</ol>\n</div>"},{"problem_id":"unit07-0127","original_source":"cpm-CL6-130","source_lesson":"Chapter 6 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"Percent decay and contextual exponential depreciation model.","question_html":"<div class=\"card problem\" id=\"CL6-130\">\n<div class=\"problem-title\">CL 6-130</div>\n<p>Elliot's dad bought a new car for $\\$31{,}000$ in 2012. Elliot read that a new car loses about $15\\%$ of its value each year. Make a table for the predicted value of the car for the first $5$ years, then write a function that represents the value in $t$ years.</p>\n</div>"},{"problem_id":"unit07-0128","original_source":"cpm-7-17","source_lesson":"7.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Fits and interprets an exponential model for mold-growth data.","question_html":"<section class=\"problem\" id=\"7-17\">\n<h2>7-17</h2>\n<div class=\"meta\"><span class=\"pill\">Review/Preview</span><span>Sorted to Unit 7, Section 5</span></div>\n<div class=\"audit\">Audit note: Fits and interprets an exponential model for mold growth data.</div>\n<div class=\"problem-body\"><div class=\"row\"><div class=\"col-sm-9\"><p class=\"\" style=\"\">Eeeeew! Hannah\u2019s volleyball team left their egg salad sandwiches sitting in their lockers over the weekend. When they got back on Monday they were moldy. \u201cPerfect!\u201d said Hannah. \u201cI can use these sandwiches for my biology project. I\u2019ll study how quickly mold grows.\u201d</p><p class=\"\" style=\"\">Using a transparent grid, Hannah estimated that about $12\\%$ of the surface of one sandwich had mold on it. She threw the sandwich out. For the rest of the week, Hannah came back when she had time. Each time she measured somebody else\u2019s sandwich and threw it out. She collected the following data: </p></div></div><table class=\"data-table\" style=\"margin: 0 auto;\"><tbody><tr><th><p class=\"\" style=\"text-align: center\">Day 1<br/> (Monday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 2<br/> (Tuesday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 2<br/> (Tuesday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 4<br/> (Thursday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 4<br/> (Thursday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 4<br/> (Thursday)</p></th><th><p class=\"\" style=\"text-align: center\">Day 5<br/> (Friday)</p></th></tr><tr><td><p class=\"\" style=\"text-align: center\">$12\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$15\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$13\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$26\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$27\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$24\\%$</p></td><td><p class=\"\" style=\"text-align: center\">$38\\%$</p></td></tr></tbody></table><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Create a scatterplot and sketch it. Is a linear model reasonable? <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/itusz03ipb\" rel=\"noopener\" target=\"_blank\"><em>7-17 HW eTool</em></a></p></li><li><p class=\"\" style=\"\">Based on the story, what kind of equation do you think will best fit the situation?</p></li><li><p class=\"\" style=\"\">Fit the data with an exponential model and write the equation. What percentage of a sandwich did Hannah predict was covered on Wednesday? Consider the precision of Hannah\u2019s measurements when deciding how many decimal places to use in your answer.</p></li></ol></div>\n</section>","resources":[{"label":"7-17 HW eTool","href":"https://www.desmos.com/calculator/itusz03ipb"}]},{"problem_id":"unit07-0129","original_source":"cpm-7-29","source_lesson":"7.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Contextual exponential growth/decay model and interpretation.","question_html":"<section class=\"problem\" id=\"7-29\">\n<h2>7-29</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 5: Linear Modeling with Data</div>\n<div class=\"audit\">Audit note: Interprets correlation and residual-plot evidence in context.</div>\n<div><p>Scientists hypothesized that dietary fiber would impact the blood cholesterol level of college students. They collected data and found <em>$r=-0.45$</em> with a scattered residual plot. Interpret the scientists\u2019 findings in context.</p></div>\n</section>"},{"problem_id":"unit07-0130","original_source":"cpm-7-30","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Compares simple and compound interest using tables, percent growth, and contextual interpretation.","question_html":"<section class=\"problem\" id=\"7-30\">\n<h2>7-30</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Compares simple and compound interest using tables, percent increase, and growth structure.</div>\n<div><div><div><p>SAVING FOR COLLEGE</p><p>Suppose you have \\$1000 to invest and know of two investment options. You can invest in bonds (which pay $8\\%$ <em>simple</em> interest) or put your money in a credit union account (which pays $8\\%$ <em>compound</em> interest). Will the option you choose make a difference in the amount of money you earn? Examine these two situations below.</p></div><div></div></div><div><div><p><strong>Bonds with Simple Interest:</strong></p><ol class=\"lower-alpha\" type=\"a\"><li><p>If you invest in bonds, your \\$1000 would grow as shown in the table at right. How does money grow with simple interest?</p></li><li><p>By what percent would your balance have increased at the $4^{\\text{th}}$ year? Show how you know.</p></li></ol></div><div><p><strong>VALUE OF BONDS</strong></p><table><tbody><tr><th><p><strong>Number of Years</strong></p></th><th><p><strong>Amount of Money</strong><br/> <strong>(in dollars)</strong></p></th></tr><tr><td><p>$0$</p></td><td><p>$1000.00$(initial value)</p></td></tr><tr><td><p>$1$</p></td><td><p>$1080.00$</p></td></tr><tr><td><p>$2$</p></td><td><p>$1160.00$</p></td></tr><tr><td><p>$3$</p></td><td><p>$1240.00$</p></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></div></div><div><div><p><strong>Accounts with Compound Interest:</strong></p><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>Instead, if you invest your \\$1000 in the credit union at $8\\%$ compound interest that is compounded once a year, its value would grow as shown in the table at right. Why is there \\$1166.40 in your account at the second year? Explain how the compound interest is calculated. How is it growing?</p></li></ol><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>What will be the balance of the credit-union account at the $4^{\\text{th}}$ year? By what percent would this account balance increase at four years? Show how you know.</p></li><li><p>Which type of account \u2013 a bond with simple interest or a credit union account with compound interest \u2013 grows most quickly?</p></li></ol></div><div><p><strong>VALUE OF CREDIT-UNION ACCOUNT</strong></p><table><tbody><tr><th><p><strong>Number of Years</strong></p></th><th><p><strong>Amount of Money</strong><br/> <strong>(in dollars)</strong></p></th></tr><tr><td><p>$0$</p></td><td><p>$1000.00$ (initial value)</p></td></tr><tr><td><p>$1$</p></td><td><p>$1080.00$</p></td></tr><tr><td><p>$2$</p></td><td><p>$1166.40$</p></td></tr><tr><td><p>$3$</p></td><td><p>$1259.71$</p></td></tr><tr><td><p>$4$</p></td><td></td></tr></tbody></table></div></div></div>\n</section>"},{"problem_id":"unit07-0131","original_source":"cpm-7-31","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Graphs and compares growth behavior of simple and compound interest.","question_html":"<section class=\"problem\" id=\"7-31\">\n<h2>7-31</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Graphs simple and compound interest over time and compares their growth behavior.</div>\n<div><p> Assume that the interest is added at the beginning of a new year. Make one graph that shows how each type of investment (simple and compound) starts with \\$1000 and grows over $8$ years. Discuss these questions in your team as you graph:</p></div>\n</section>"},{"problem_id":"unit07-0132","original_source":"cpm-7-32","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Creates simple- and compound-interest models and uses them for long-term prediction.","question_html":"<section class=\"problem\" id=\"7-32\">\n<h2>7-32</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models simple and compound interest with equations and uses the model for long-term prediction.</div>\n<div><div><div><p>In the previous chapter you used models as an estimate of real behavior. Creating a linear model for scattered data gave you a mathematical way to describe the data and to make predictions.</p><p>Simple and compound interest in problem 7-31 were both <strong>step functions</strong>. Writing equations for step functions can be very complicated. However, we can model the step functions with other equations we are already familiar with.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Think about the growth and the starting point for the simple and compound interest situations from this lesson. Model each of the two step functions with an equation. Let <em>y</em>represent the money in the account after <em>$x$</em> years.</p></li><li><p>Check that your equation represents the tables in problem 7-30. If your models do not match the tables, correct your equation.</p></li><li><p>Use your model to predict how much your original \\$1000 investment would be worth at the end of $20$ years in the credit union.</p></li><li><p>Why are the equations considered a model, instead of a representation of the real behavior? Is there an advantage to using the model to make predictions?</p></li></ol></div><div></div></div></div>\n</section>"},{"problem_id":"unit07-0133","original_source":"cpm-7-33","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Builds a quarterly compound-interest model and compares investment options.","question_html":"<section class=\"problem\" id=\"7-33\">\n<h2>7-33</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Builds a quarterly compound-interest model using a periodic multiplier.</div>\n<div><div><div><p>From now on in this course, we will use continuous functions to model situations, unless indicated otherwise. <strong></strong></p><p>A third option for investing money is a money market account, which offers $8\\%$ annual interest <em>compounded quarterly</em> (four times per year). This means that the $8\\%$ is divided into four parts over the year, so the bank pays $2\\%$ every three months.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Model the value (every three months) of the \\$1000 investment in this money market account with an equation. Let <em>$y$</em>represent the money in the account after <em>$x$</em> quarters.</p></li><li><p>Use the model to find the value of your \\$1000 investment at four years. How does this compare with your other investment options from problem 7-30?</p></li></ol></div><div></div></div></div>\n</section>"},{"problem_id":"unit07-0134","original_source":"cpm-7-34","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses exponential growth models to compare investment outcomes and rates.","question_html":"<section class=\"problem\" id=\"7-34\">\n<h2>7-34</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Compares compound-interest growth with simple-interest growth over a long time horizon.</div>\n<div><p>If you invested \\$1000 in the credit union from problem 7-30 (interest compounded yearly at $8\\%$), how much would you have at $20$ years? If you wanted to earn this same amount of money with bonds with simple interest, what interest rate would the bonds need to earn? Show how you know.</p></div>\n</section>"},{"problem_id":"unit07-0135","original_source":"cpm-7-35","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Interprets an investment graph and writes an exponential model.","question_html":"<section class=\"problem\" id=\"7-35\">\n<h2>7-35</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Interprets an investment graph, distinguishes simple versus compound interest, and writes a model.</div>\n<div><div><div><p>Your banker shows you the graph at right to explain what you can earn if you invest with him. Does this graph represent simple or compound interest? How can you tell? Write an equation to represent how much money you would have as time passes. Make sure you write a \u201clet\u201d statement.</p></div><div><p><div><img alt=\"Captured figure for 7-35\" class=\"figure-img\" src=\"assets/7-35.png\"/></div></p></div></div></div>\n</section>"},{"problem_id":"unit07-0136","original_source":"cpm-7-37","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses a daily multiplier to model ticket-price growth and make predictions.","question_html":"<section class=\"problem\" id=\"7-37\">\n<h2>7-37</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses a daily multiplier to model exponential ticket-price growth forward and backward in time.</div>\n<div><p>Tickets for a concert have been in incredibly high demand, and as the date for the concert draws closer, the price of tickets increases exponentially. The cost of a pair of concert tickets was \\$150 yesterday, and today it is \\$162. As you complete parts (a) through (c) below, assume that each day\u2019s percent increase from the day before is the same.</p><ol class=\"lower-alpha\"><li><p>What is the daily percent rate of increase? What is the multiplier?</p></li><li><p>What will be the cost of a pair of concert tickets one week from now?</p></li><li><p>What was the cost of a pair of tickets two weeks ago?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0137","original_source":"cpm-7-38","source_lesson":"7.1.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compound-interest model and future-value prediction.","question_html":"<section class=\"problem\" id=\"7-38\">\n<h2>7-38</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Writes and evaluates an annual compound-interest model.</div>\n<div><p>Dusty won \\$125{,}000 on the <em>Who Wants to be a Zillionaire?</em> game show. He decides to place the money into an account that earns $6.25\\%$ interest compounded annually and plans not to use any of it until he retires.</p><ol class=\"lower-alpha\" type=\"a\"><li><p>Write an expression that represents how much money Dusty will have in <em>$t$</em> years.</p></li><li><p>How much money will be in the account when he retires in $23$ years?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0138","original_source":"cpm-7-42","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Penny-lab decay experiment modeling repeated proportional loss.","question_html":"<section class=\"problem\" id=\"7-42\">\n<h2>7-42</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models exponential decay through a penny-removal experiment and reasons about starting value and multiplier.</div>\n<div class=\"contentContainerReference-body\"><div><div><p class=\"\">THE PENNY LAB  \t</p><p class=\"\">What about situations that do not grow? In this activity, you will explore a situation that behaves exponentially, but results get smaller.\u00a0 This is an example of<strong> exponential decay</strong>.</p><p class=\"\"><strong>Your Task:</strong> Follow the directions below to model exponential decay using pennies.\u00a0</p></div><div><p class=\"\"><strong></strong></p></div></div><div><div><p class=\"\">Trial #$0$:</p></div><div><p class=\"\">Start with $100$ pennies.</p></div></div><div><div><p class=\"\">Trial #$1$:</p></div><div><p class=\"\">Dump the pennies out on your team\u2019s workspace. Remove any pennies that have \u201ctails\u201d side up. Record the number of pennies that <em>remain</em> in a table where the input is the trial number and the output is the number of \u201cheads.\u201d</p></div></div><div><div><p class=\"\">Trial #$2$:</p></div><div><p class=\"\">Gather the \u201cheads-up\u201d pennies, shake them up, and dump them on your workspace again. Remove any pennies that have the \u201ctails\u201d side up and count the number of pennies that remain.</p></div></div><div><div><p class=\"\">Trial #<em>$x$</em>:</p></div><div><p class=\"\">Continue this process until the last penny is removed. Be sure to record all of your results in your table and then answer the questions below.</p></div></div><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">Is it possible that a team conducting this experiment might never remove their last penny? Explain.\u00a0</p></li><li><p class=\"\">Would the results of this experiment have been significantly different if you had removed the \u201cheads\u201d pennies each time?\u00a0</p></li><li><p class=\"\">If you had started with $200$ pennies, how would this have affected the results?\u00a0</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0139","original_source":"cpm-7-43","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Graphs penny-lab data, estimates multiplier, writes a model, and interprets context.","question_html":"<section class=\"problem\" id=\"7-43\">\n<h2>7-43</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Graphs penny-lab data, describes decay behavior, estimates a multiplier, and writes an exponential model.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Decide what your dependent and independent variables are for \u201cThe Penny Lab\u201d data, clearly label them, and graph your data on your own graph paper. Then graph your data carefully on a team <a href=\"http://pdfs.cpm.org/stuRes/CCA/chapter_07/CCA%20Lesson%207.1.4%20RP.pdf\" rel=\"noopener\" target=\"_blank\">Lesson 7.1.4 Resource Page</a> obtained from your teacher or using the\u00a0<a href=\"https://www.desmos.com/calculator/sbno1msb85\" rel=\"noopener\" target=\"_blank\"><em>7-42 &amp; 7-43 eTool</em></a>.\u00a0</p><p class=\"etool-note\">Interactive eTool referenced in original lesson.</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">Include your team\u2019s data with those from other teams to present to the class. Then examine and describe the resulting scatterplot. Where does the graph cross the <em>$y$</em>-axis? Does the graph have any asymptotes? Should the graph be continuous or discrete? \u00a0\u00a0\u00a0</p></li><li><p class=\"\">Is this situation increasing or decreasing? What does this mean about the multiplier? Using what you know about the probability of flipping a fair coin, what would you expect or estimate the multiplier to be?\u00a0</p></li><li><p class=\"\">Write an equation for an exponential function that models the data. Make sure you also write a \u201clet\u201d statement for your variables. \u00a0</p></li><li><p class=\"\">What output does your function give for <em>$x = 0$</em>? What could this mean in relation to the situation? \u00a0\u00a0</p></li><li><p class=\"\">Could there be an output value for <em>$x = \u22121$</em>? If so, what might it mean?</p></li><li><p class=\"\">In the context of this situation, what should the domain of the model that you wrote in part (c) be? With the appropriate domain, what would a graph of your model look like?\u00a0</p></li><li><p class=\"\">What family of functions that you saw in previous chapters has graphs like the one you made in part (f)? What are the first few values of this function? What is the equation? \u00a0\u00a0</p></li></ol></div>\n</section>","resources":[{"label":"Lesson 7.1.4 Resource Page","href":"http://pdfs.cpm.org/stuRes/CCA/chapter_07/CCA%20Lesson%207.1.4%20RP.pdf"},{"label":"7-42 & 7-43 eTool","href":"https://www.desmos.com/calculator/sbno1msb85"}]},{"problem_id":"unit07-0140","original_source":"cpm-7-44","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Half-life modeling and interpretation of exponential decay.","question_html":"<section class=\"problem\" id=\"7-44\">\n<h2>7-44</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses half-life to model exponential decay and interpret outputs at different numbers of half-lives.</div>\n<div class=\"contentContainerReference-body\"><div><div><p class=\"\">HALF-LIFE</p><p class=\"\">Carbon-$14$ dating is used to approximate the age of ancient discoveries and to learn more about things like dinosaur fossils.\u00a0 Scientists have studied the rate of decay of carbon-$14$ and have learned that no matter how much of this element they start with, only half of it will remain after about $5730$ years (which is called its<strong> half-life</strong>).</p></div><div><p class=\"\"></p></div></div><p class=\"\">All living things on this planet contain the same proportion of this carbon-$14$ relative to overall carbon in their bodies. Knowing how much carbon-$14$ to expect, scientists can then measure how much carbon-$14$ is left in ancient items to figure out how much time has passed since the object was living. \t</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">If a living object is supposed to contain $100$ grams of carbon-$14$, how much would be expected to remain after one half-life ($5730$ years)? After two half-lives ($11,460$ years)?\u00a0</p></li><li><p class=\"\">Draw a graph showing the expected amount, <em>$y$</em>, of carbon-$14$ (in grams) remaining after <em>$x$</em> half-lives.\u00a0\u00a0</p></li><li><p class=\"\">Write an equation for a function that represents the amount of carbon-$14$ that will remain after <em>$x$</em> half-lives.\u00a0Write a \u201clet\u201d statement.\u00a0</p></li><li><p class=\"\">What output does your function give for<em> $x=0$</em>? Does this make sense? Justify why or why not. \u00a0</p></li><li><p class=\"\">What output would the function give for <em>$x=\u22121$</em>?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0141","original_source":"cpm-7-48","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Depreciation model, multiplier, prediction, graph, and interpretation.","question_html":"<section class=\"problem\" id=\"7-48\">\n<h2>7-48</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models depreciation as exponential decay and interprets value over time.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Assume that a DVD loses $60\\%$ of its value every year it is in a video store. Suppose the initial value of the DVD was $\\$80$. <a href=\"https://www.desmos.com/calculator/exqk6fjqvm\" rel=\"noopener\" target=\"_blank\"><em><span></span></em></a><span>\u00a0</span><a href=\"https://www.desmos.com/calculator/ej9iqgao77\" rel=\"noopener\" target=\"_blank\"><em><span><span>7-48 HW eTool</span></span></em></a>\u00a0\u00a0</p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">What multiplier would you use to calculate the video\u2019s new values?</p></li><li><p class=\"\">What is the value of the DVD after one year? After four years?</p></li><li><p class=\"\">Write a continuous function, <em>$V\\left(t\\right)$</em>, to model the value of a DVD after <em>$t$</em> years.</p></li><li><p class=\"\">When does the video have no value?</p></li><li><p class=\"\">Sketch a graph of this function. Be sure to scale and label the axes.</p></li></ol></div>\n</section>","resources":[{"label":"https://www.desmos.com/calculator/exqk6fjqvm","href":"https://www.desmos.com/calculator/exqk6fjqvm"},{"label":"7-48 HW eTool","href":"https://www.desmos.com/calculator/ej9iqgao77"}]},{"problem_id":"unit07-0142","original_source":"cpm-7-54","source_lesson":"7.1.4","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compound-interest interpretation and model writing.","question_html":"<section class=\"problem\" id=\"7-54\">\n<h2>7-54</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Interprets the multiplier in a monthly compound-interest equation and writes a related model.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Jerry says, \u201cI\u2019ve got my money in a great account that compounds interest monthly. The equation<em> $y = 388\\left(1.008\\right)^{m}$</em> represents how much money I have at the end of any month.\u201d What is Jerry\u2019s monthly interest rate? Write an equation to represent your total money if you invest $$500$ in an account with the same rate of return. Let <em>$m$</em> represent the number of months the money has been invested. </p></div>\n</section>"},{"problem_id":"unit07-0143","original_source":"cpm-7-63","source_lesson":"7.1.5","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compound-interest model, prediction, and contextual interpretation.","question_html":"<section class=\"problem\" id=\"7-63\">\n<h2>7-63</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models compound interest and interprets domain and range in context.</div>\n<div><p>Kristin\u2019s grandparents started a savings account for her when she was born. They invested \\$500 in an account that pays $8\\%$ interest compounded annually.</p><ol class=\"lower-alpha\"><li><p>Write an equation to model the amount of money in the account on Kristin\u2019s <em>$x^{th}$</em> birthday.</p></li><li><p>How much money is in the account on Kristin\u2019s 16<sup>th</sup> birthday?</p></li><li><p>What are the domain and range of the equation that you wrote in part (a)?</p></li></ol></div>\n</section>"},{"problem_id":"unit07-0144","original_source":"cpm-7-67","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Creates realistic situations to match exponential representations; modeling objective dominates.","question_html":"<section class=\"problem\" id=\"7-67\">\n<h2>7-67</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Creates real-world situations to match exponential representations, including a graph, an equation, and a table.</div>\n<p>WRITING A SITUATION</p>\n<p>Each representation below represents a different set of data. For each part, brainstorm a situation that could fit the data. Provide enough information in your \u201cproblem\u201d description so that someone else could generate the graph, table, or equation for the data. Be creative! Your team\u2019s situation may be selected for a future assessment!</p>\n<img alt=\"Captured representations for 7-67, parts a through c.\" class=\"figure-img wide-figure\" src=\"assets/7-67.png\"/>\n</section>"},{"problem_id":"unit07-0145","original_source":"cpm-7-68","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Exponential decay situation interpreted through a graph and long-term behavior.","question_html":"<section class=\"problem\" id=\"7-68\">\n<h2>7-68</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models exponential decay from a real-world situation and interprets long-term behavior from the graph.</div>\n<p>SITUATION \u2192 GRAPH</p>\n<p>A virus has invaded Leticia\u2019s favorite mountain fishing lake. Currently there are an estimated $1800$ trout in the lake, and the Fish and Game Department has determined that the rate of fish deaths will be one third of the population per week if left untreated.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>Sketch a graph showing how many fish are left in Leticia\u2019s favorite lake over several weeks.</p></li>\n<li><p>Theoretically, will the trout ever completely disappear from the lake? Use the graph to justify your answer.</p></li>\n</ol>\n</section>"},{"problem_id":"unit07-0146","original_source":"cpm-7-69","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Writes a model from a contextual graph, predicts, extrapolates, and evaluates accuracy.","question_html":"<section class=\"problem\" id=\"7-69\">\n<h2>7-69</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Writes and uses an exponential model from a contextual graph, then evaluates interpolation, extrapolation, and model accuracy.</div>\n<div class=\"row\"><div>\n<p>GRAPH \u2192 EQUATION</p>\n<p>Suppose the annual fees for attending a public university were \\$7000 in 2010 and the annual cost can be seen in the graph at right. Note that <em>x</em> represents the number of years after 2010.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>Write an equation to describe this situation.</p></li>\n<li><p>Use this model to predict the cost of attending a public university in the first year you would be eligible to enroll.</p></li>\n<li><p>What was the cost in 2000, assuming the rate of increase was the same during the time period from 2000 to 2010?</p></li>\n<li><p>Are you confident with your prediction in part (c)? Explain.</p></li>\n<li><p>In 2012 the annual cost was actually \\$8244. How accurate was the model? What actually happened?</p></li>\n</ol>\n</div><div><img alt=\"Captured exponential graph for 7-69.\" class=\"figure-img\" src=\"assets/7-69.png\"/></div></div>\n</section>"},{"problem_id":"unit07-0147","original_source":"cpm-7-71","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Growth, decay, radioactive decay, population growth, and compound-interest applications.","question_html":"<section class=\"problem\" id=\"7-71\">\n<h2>7-71</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Builds exponential models from growth, decay, and compound-interest situations and uses them to answer contextual questions.</div>\n<p>SITUATION \u2192 ?</p>\n<p>Use each of the situations below to complete missing pieces of the web or to practice moving from a situation directly to a specific representation. For each part, decide which representation you will generate from the situation description based on where your team needs to work.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>A $100$-gram sample of a radioactive isotope decays at a rate of $6\\%$ every week. How big will the sample be one year from now?</p></li>\n<li><p>The math club is fast becoming one of the most popular clubs on campus because of the fabulous activities it sponsors annually for Pi Day on March $14$. Each year, the club\u2019s enrollment increases by $30\\%$. If the club has $45$ members this year, how many members should it expect to have $5$ years from now?</p></li>\n<li><p>Barbara made a bad investment. Rather than earning interest, her money is decreasing in value by $11\\%$ each week! After just one week, she is down to just \\$142.40. How much money did she start with? If she does not withdraw her money, how long will it be before she has less than half of what she originally invested?</p></li>\n<li><p>Larry loves music. He bought \\$285 worth of MP3 files on his credit card, and now he cannot afford to pay off his debt. If the credit-card company charges him $18\\%$ annual interest compounded monthly, how does Larry\u2019s debt grow as time passes? How much would he owe at the end of the year if he had a \u201cno payments for $12$ months\u201d feature for his credit card?</p></li>\n</ol>\n</section>"},{"problem_id":"unit07-0148","original_source":"cpm-7-72","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Learning Log","audit_status":"authoritative","notes":"Synthesizes major ideas about exponential functions through contextual applications.","question_html":"<section class=\"problem\" id=\"7-72\">\n<h2>7-72</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Synthesizes the main ideas of exponential functions across representations and contexts.</div>\n<p>LEARNING LOG</p>\n<p>Consider all of the things you have learned so far in this chapter. If you were creating a presentation for families for Open House Night and wanted to teach them the main ideas about exponential functions, what would they be? Write a Learning Log entry describing the main ideas and why they are important. Title this entry \u201cImportant Ideas about Exponential Functions\u201d and include today\u2019s date.</p>\n</section>"},{"problem_id":"unit07-0149","original_source":"cpm-7-73","source_lesson":"7.1.6","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Population-growth model and residual interpretation.","question_html":"<section class=\"problem\" id=\"7-73\">\n<h2>7-73</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses an exponential population model to predict, compare to actual data, and interpret a residual.</div>\n<p>The U.S. Census Bureau takes a census every $10$ years. The population in $2000$ was estimated at $281.4$ million people. A model created at the time predicted that the population grew at about $2\\%$ per year.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>How many people would the Census Bureau have expected to count in the $2005$ census?</p></li>\n<li><p>If the Census Bureau had conducted a count in $2010$, how many people would it have expected to count?</p></li>\n<li><p>The actual $2010$ census put the population at $309$ million people. What is the residual? What does it mean?</p></li>\n</ol>\n</section>"},{"problem_id":"unit07-0150","original_source":"cpm-7-102","source_lesson":"7.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Appreciation/depreciation comparison among multiple vehicles using exponential models.","question_html":"<article class=\"problem\" id=\"7-102\">\n<h3>7-102.</h3>\n<div class=\"meta\"><span class=\"tag\">Lesson</span><span>Sorted to Unit 7, Section 5: Exponential Modeling</span></div>\n<div class=\"audit\">Audit note: Models depreciation and appreciation with exponential functions and compares car values over time using multiple representations.</div>\n<p><strong>FAST CARS</strong></p>\n<p>The moment you drive a new car off the dealer's lot, the car is worth less than what you paid for it. This phenomenon is called <em>depreciation</em>, which means you will sell the car for less than the price that you paid for it. Some cars depreciate more than others, but most cars depreciate over time. On the other hand, some older cars actually increase in value. This is called <em>appreciation</em>.</p>\n<p>Suppose that in $2012$, Jeralyn had a choice between buying a $2010$ Fonda Concord EX for $\\$27{,}000$, which depreciates at $6\\%$ per year; a $2010$ Padillac Escalate for $\\$39{,}000$, which depreciates at $22.5\\%$ per year; or a $1967$ Fyord Rustang for $\\$15{,}000$ that is appreciating at $10\\%$ per year.</p>\n<p><strong>Your Task:</strong> Investigate the value of each of the three cars over time.</p>\n<ul>\n<li>Generate multiple representations of the value of each car over time.</li>\n<li>For each of the new cars, determine how much value they lost, in dollars, from the time they were new in $2010$ until $2012$.</li>\n<li>Decide which car Jeralyn should buy and defend your choice in as many ways as you can.</li>\n</ul>\n<h4 class=\"note-heading\">Discussion Points</h4>\n<p class=\"center\">What is the multiplier?</p>\n<p class=\"center\">How can we represent this situation in a table? A graph? An equation?</p>\n<p class=\"center\">What should we consider when deciding which car to buy?</p>\n</article>"},{"problem_id":"unit07-0151","original_source":"cpm-7-103","source_lesson":"7.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Builds tables, graphs, equations, and predictions for depreciation/appreciation models.","question_html":"<article class=\"problem\" id=\"7-103\">\n<h3>7-103.</h3>\n<div class=\"meta\"><span class=\"tag\">Lesson</span><span>Sorted to Unit 7, Section 5: Exponential Modeling</span></div>\n<div class=\"audit\">Audit note: Builds tables, graphs, equations, and comparisons for depreciation/appreciation models.</div>\n<p>Investigate the changing values of each of the cars by addressing the questions below.</p>\n<ol class=\"lower-alpha\">\n<li>What is the multiplier for the Concord? For the Escalate? For the Rustang?</li>\n<li>Make a table like the one below and calculate the value for each car for each year shown.\n        <table>\n<tr><th>Year</th><th>Concord</th><th>Escalate</th><th>Rustang</th></tr>\n<tr><td>$0$</td><td>$\\$27{,}000$</td><td>$\\$39{,}000$</td><td>$\\$15{,}000$</td></tr>\n<tr><td>$1$</td><td>$\\$25{,}380$</td><td>$\\$30{,}225$</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$2$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$3$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$4$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$5$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$\\ldots$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$10$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$\\ldots$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n<tr><td>$n$</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td><td class=\"blank\">\u00a0</td></tr>\n</table>\n</li>\n<li>On your own graph paper, graph the data for all three cars on the same set of axes. Are the graphs linear? How are they similar? How are they different? You may want to use a different color for each car.</li>\n<li>Write a function to represent the value of each car.</li>\n<li>What were the values of the Concord and the Escalate when they were new? How much value, in dollars, did each car lose from $2010$ to $2012$?</li>\n<li>Using the graph, which of the three cars is worth the most after one year? After $3$ years? After $10$ years? In how many years will the values of the Concord and Escalate be the same?</li>\n<li>Pick one of the three cars and explain why Jeralyn should buy it. Has this problem changed your view of buying cars?</li>\n</ol>\n</article>"},{"problem_id":"unit07-0152","original_source":"cpm-7-104","source_lesson":"7.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Uses half-life ideas to interpret depreciation and long-term behavior.","question_html":"<article class=\"problem\" id=\"7-104\">\n<h3>7-104.</h3>\n<div class=\"meta\"><span class=\"tag\">Lesson</span><span>Sorted to Unit 7, Section 5: Exponential Modeling</span></div>\n<div class=\"audit\">Audit note: Connects exponential depreciation to half-life and long-run model behavior.</div>\n<p>As you saw in \u201cThe Penny Lab,\u201d half-life applies to situations other than radioactive decay. In fact, the idea can be applied to anything that is depreciating or decaying exponentially.</p>\n<ol class=\"lower-alpha\">\n<li>From the values in problem 7-102, Fast Cars, estimate the half-life of the value of the Concord and the Escalate.</li>\n<li>According to the mathematical model, when will each car have no value?</li>\n</ol>\n</article>"},{"problem_id":"unit07-0153","original_source":"cpm-7-105","source_lesson":"7.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Creates a depreciation model from real-world data and interprets depreciation rate.","question_html":"<article class=\"problem\" id=\"7-105\">\n<h3>7-105.</h3>\n<div class=\"meta\"><span class=\"tag\">Lesson</span><span>Sorted to Unit 7, Section 5: Exponential Modeling</span></div>\n<div class=\"audit\">Audit note: Writes an exponential depreciation equation from two real-world values and interprets the depreciation rate.</div>\n<p>In $2009$, a brand new SUV cost $\\$35{,}000$ to drive off the lot. In $2012$ that same SUV was valued at $\\$22{,}500$. Write an exponential equation to represent this information. Then find the rate of depreciation for the SUV.</p>\n</article>"},{"problem_id":"unit07-0154","original_source":"cpm-CL7-117","source_lesson":"Chapter 7 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"Stock depreciation model, multiplier, percent decrease, and prediction.","question_html":"<div class=\"card\" id=\"CL7117\">\n<div class=\"problem-title\">CL 7-117</div>\n<p>A share of ABC stock was worth $\\$60$ in $2005$ and only worth $\\$45$ in $2010$.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>Find the multiplier and the percent decrease.</li>\n<li>Write an exponential function that models the value of the stock starting from $2005$.</li>\n<li>Assuming that the decline in value continues at the same rate, use your answer to part (b) to predict the value in $2020$.</li>\n</ol>\n</div>"},{"problem_id":"unit07-0155","original_source":"cpm-CL7-120","source_lesson":"Chapter 7 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"House appreciation, bacteria growth, depreciation, and compound-interest models.","question_html":"<div class=\"card\" id=\"CL7120\">\n<div class=\"problem-title\">CL 7-120</div>\n<p>Below are several situations that can be described using exponential functions. They represent a small sampling of the situations where quantities grow or decay by a constant percentage over equal periods of time. For each situation (a) through (d):</p>\n<ul>\n<li>Find an appropriate unit of time, such as days, weeks, or years.</li>\n<li>Find the multiplier that should be used.</li>\n<li>Identify the initial value.</li>\n<li>Write an exponential equation in the form $y=ab^x$ that represents the growth or decay.</li>\n</ul>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>A house purchased for $\\$120{,}000$ has an annual appreciation of $6\\%$.</li>\n<li>The number of bacteria present in a colony is $180$ at noon, and it increases at a rate of $22\\%$ per hour.</li>\n<li>The value of a car with an initial purchase price of $\\$12{,}250$ depreciates by $11\\%$ per year.</li>\n<li>An investment of $\\$1000$ earns $6\\%$ annual interest, compounded monthly.</li>\n</ol>\n</div>"},{"problem_id":"unit07-0156","original_source":"cpm-8-20","source_lesson":"8.1.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses exponential decay model to predict stock value.","question_html":"<article class=\"problem\" id=\"8-20\">\n<h3>8-20.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 7, Section 5: Exponential Modeling</span></div>\n<div class=\"audit\">Audit note: Applies an exponential decay model to predict a future stock value.</div>\n<p>The value of Bulls Eye stock has decreased $8\\%$ each year for the past several years. If in 2010 the stock was worth $\\$50$ and that pattern continues, how much will it be worth in 2015?</p>\n</article>"},{"problem_id":"unit07-0157","original_source":"cpm-CL8-113","source_lesson":"Chapter 8 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"Percent growth and exponential prediction.","question_html":"<div class=\"card\" id=\"CL8113\">\n<div class=\"problem-title\">CL 8-113</div>\n<p>The price of milk has been steadily increasing $5\\%$ per year. If the cost of a gallon is now $\\$3.89$:</p>\n<div class=\"grid-2\">\n<ol type=\"a\"><li>What will it cost in $10$ years?</li></ol>\n<ol start=\"2\" type=\"a\"><li>What did it cost $5$ years ago?</li></ol>\n</div>\n</div>"},{"problem_id":"unit07-0158","original_source":"cpm-9-88","source_lesson":"9.3.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential-model interpretation and prediction.","question_html":"<section class=\"problem\" id=\"9-88\">\n<h2>9-88</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 6, Section 3: Quadratic Formula</div>\n<div class=\"audit\">Audit note: Determines the number of x-intercepts of a quadratic using two matching methods.</div>\n<div>\n<p>Determine the number of times the graph of $y=5x^2+7x-6$ intersects the $x$-axis using <em>two different methods</em>. The answers from each method should match.</p>\n</div>\n</section>"},{"problem_id":"unit07-0159","original_source":"cpm-9-96","source_lesson":"9.4.1","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Determines annual multiplier and percent increase from contextual data.","question_html":"<section class=\"problem\" id=\"9-96\">\n<h2>9-96</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Finds an annual multiplier and percent increase from an old and new price over three years.</div>\n<div><p>Three years ago the average price of a movie ticket was $\\$8.75$ and now it is $\\$11.00$. What was the annual multiplier and the percent increase?</p></div>\n</section>"},{"problem_id":"unit07-0160","original_source":"cpm-9-110","source_lesson":"9.4.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Exponential-model interpretation and prediction.","question_html":"<section class=\"problem\" id=\"9-110\">\n<h2>9-110</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Other: Solving and Graphing Inequalities</div>\n<div class=\"audit\">Audit note: Writes and graphs business constraints as a system of inequalities with a feasible region; keeps the useful Desmos HW eTool link.</div>\n<div>\n<p>For the Spring Festival, the Math Club is selling rulers for $\\$1$ and compasses for $\\$2.50$. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/jprolpze9m\" rel=\"noopener\" target=\"_blank\">9-110 HW eTool</a></p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li><p>While the club would like to sell as many items as they can to raise funds, they need to make at least $\\$15.00$ to break even. Write an inequality to represent this situation. Let $r=$ the number of rulers sold and $c=$ the number of compasses sold.</p></li>\n<li><p>School rules state that the club can sell a maximum of $25$ items for the festival. Write an inequality for this constraint.</p></li>\n<li><p>Graph the inequalities from parts (a) and (b) on the same set of axes so that compasses are represented on the $x$-axis and rulers are represented on the $y$-axis. Find the region of points that are solutions to each of them. Can this region fall below the $x$-axis or to the left of the $y$-axis? Why or why not?</p></li>\n<li><p>What do the points in the solution region represent?</p></li>\n</ol>\n</div>\n</section>","resources":[{"label":"9-110 HW eTool","href":"https://www.desmos.com/calculator/jprolpze9m"}]},{"problem_id":"unit07-0161","original_source":"cpm-CL9-129","source_lesson":"Chapter 9 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"DVD-rental decay model and prediction.","question_html":"<div class=\"card\" id=\"CL9129\">\n<div class=\"problem-title\">CL 9-129</div>\n<p>The cost to rent a DVD has decreased $10\\%$ per year over the past several years.</p>\n<ol type=\"a\">\n<li>If the current cost is $\\$5$, write an exponential equation describing this situation.</li>\n<li>According to the equation, what did it cost to rent a DVD $5$ years ago?</li>\n</ol>\n</div>"},{"problem_id":"unit07-0162","original_source":"cpm-10-19","source_lesson":"10.1.1","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"10-19\">\n<h2>10-19</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Models repeated percent increase forward and backward in time.</div>\n<div>\n<p>The cost of a loaf of bread is now $\\$2.79$ and has been increasing $8\\%$ per year for several years.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>At the same rate, what will it cost in $5$ years?</li>\n<li>What did it cost $5$ years ago?</li>\n</ol>\n</div>\n</section>"},{"problem_id":"unit07-0163","original_source":"cpm-10-58","source_lesson":"10.2.3","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"10-58\">\n<h2>10-58</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Determines an annual multiplier and writes an exponential depreciation model from two values.</div>\n<p>Over a three-year period, the value of a vintage VHS tape of \u201cCharlene\u2019s Greatest Hits\u201d decreased from $\\$20$ to $\\$1.99$.</p>\n<ol class=\"lower-alpha\" type=\"a\">\n<li>What were the annual multiplier and annual percent decrease?</li>\n<li>Write the equation of the function that describes this situation.</li>\n</ol>\n</section>"},{"problem_id":"unit07-0164","original_source":"cpm-CL10-145","source_lesson":"Chapter 10 Closure","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Closure","audit_status":"authoritative","notes":"Exponential growth model, graph interpretation, and interest-rate meaning.","question_html":"<div class=\"card\" id=\"CL10145\">\n<div class=\"problem-title\">CL 10-145</div>\n<p>For the exponential function $y=20(1.06)^x$:</p>\n<ol type=\"a\">\n<li>What are the starting point ($y$-intercept) and multiplier? Sketch a graph.</li>\n<li>This function describes the yearly growth of a bank account. What percent interest does the account earn per year?</li>\n</ol>\n</div>"},{"problem_id":"unit07-0165","original_source":"cpm-11-52","source_lesson":"11.2.2","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Review/Preview","audit_status":"authoritative","notes":"Interprets parameters of an exponential decay model in context.","question_html":"<section class=\"problem\" id=\"11-52\">\n<h2>11-52</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Interprets parameters in an exponential decay model with a horizontal asymptote in context.</div>\n<p>The function $f(x)=140(0.7)^x+72$, where $x$ is the time in minutes, could represent the temperature over time of a hot cup of tea placed on the kitchen counter. What does the $72$ represent in the context of this situation? What does the $0.7$ represent?</p>\n</section>"},{"problem_id":"unit07-0166","original_source":"cpm-11-122","source_lesson":"11.3.5","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Models parade traffic growth, interprets exponential parameters, and analyzes transformations in context.","question_html":"<section class=\"problem\" id=\"11-122\">\n<h2>11-122</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses exponential growth and exponential transformation models in a parade traffic-control context; image recreated.</div>\n<p><strong>TRAFFIC CONTROL</strong></p>\n<div class=\"visual-row\"><img alt=\"Traffic increasing before the parade.\" class=\"figure medium\" src=\"assets/11-122.png\"/></div>\n<p>Of course traffic will increase on the highways just before the parade. The Texas Highway Patrol uses the expected rate of traffic to decide how many officers to put on duty. Traffic is often measured in five-minute intervals. When an officer says $50$ vehicles passed by a certain place, the officer means that $50$ vehicles passed in a period of five minutes.</p>\n<ol class=\"lower-alpha\" type=\"a\"><li>On a typical morning, $133$ vehicles pass the El Fiero Le\u00f3n bridge. But starting at 8 a.m. on parade day, the traffic increases by $19\\%$ each hour. How many cars pass the bridge as the parade starts at 4 p.m.?</li><li>The Texas Highway Patrol uses the model $n=(1.005)^v$ to plan the number of officers on duty, where $v$ is the number of vehicles in five minutes and $n$ is the number of officers needed. How many officers should they have on duty at 4 p.m.? What is the percent increase of number of officers in the model?</li><li>The model in part (b) does not account for the rowdy behavior of partying out-of-towners. For celebrations like this, the Highway Patrol likes to adjust its model by what it calls the \u201c$k$ factor.\u201d<br/><br/>If the model in part (b) is called $f(v)$, which \u201c$k$ factor\u201d do you recommend the Highway Patrol uses for the Cinco de Mayo celebration: $f(v)+k$, $f(kv)$, $k\\cdot f(v)$, or $f(v+k)$? The Highway Patrol will use $k=3$ no matter which transformation they use. Explain your choice.</li></ol>\n</section>"},{"problem_id":"unit07-0167","original_source":"cpm-11-123","source_lesson":"11.3.5","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Builds an exponential-decay model from hotel-vacancy data and interprets percent decrease.","question_html":"<section class=\"problem\" id=\"11-123\">\n<h2>11-123</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Builds an exponential-decay model from hotel-room vacancy information and interprets percent decrease.</div>\n<p><strong>HOTEL ROOMS</strong></p><p>Hotel rooms book up far in advance of the parade. The number of vacant hotel rooms decreases exponentially. Unfortunately much of the data on hotel bookings was lost in a computer crash last year. What is known is that there are $15{,}500$ hotel rooms in El Fiero Le\u00f3n and the towns surrounding it. Three months after hotels started taking reservations there were only $992$ rooms left. Write an equation that models the number of rooms left for any number of months. After how many months were there less than five rooms left? By what percent do the number of vacant rooms decrease each month?</p>\n</section>"},{"problem_id":"unit07-0168","original_source":"cpm-11-124","source_lesson":"11.3.5","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Lesson","audit_status":"authoritative","notes":"Chooses an appropriate model and extrapolates future taco sales from sparse contextual data.","question_html":"<section class=\"problem\" id=\"11-124\">\n<h2>11-124</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 7, Section 5: Exponential Modeling</div>\n<div class=\"audit\">Audit note: Uses sparse contextual data to choose a model type and make an extrapolated prediction; table preserved.</div>\n<p><strong>TACOS</strong></p><p>There are fifteen Taco Shacks along the parade route. People wait in long lines to get their famed tacos. The food director needs to predict how many tacos will be sold so that he can purchase enough supplies. Looking back at the last five years, this was all the director could find from previous Cinco de Mayo celebrations:</p>\n<table class=\"data\"><tr><th>Time of Day</th><th># Tacos Sold<br/>That Hour</th></tr><tr><td>8 a.m.</td><td>1150</td></tr><tr><td>Noon</td><td>2257</td></tr><tr><td>10 a.m.</td><td>1512</td></tr><tr><td>Noon</td><td>2091</td></tr><tr><td>8 a.m.</td><td>954</td></tr></table>\n<ol class=\"lower-alpha\" type=\"a\"><li>Based on what you have already learned about the celebration, what type of function should the food director use to model the number of tacos sold each hour?</li><li>Predict the number of tacos sold in the 7 p.m. hour. Justify your prediction to the satisfaction of the food director.</li><li>What concern do you have about the prediction you made?</li></ol>\n</section>"},{"problem_id":"unit07-0169","original_source":"cpm-CP09-01","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-01\"><h2>CP09-01</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A powerful computer is purchased for \\$2000, but on average loses 20% of its value each year. How much will it be worth 4 years from now?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0170","original_source":"cpm-CP09-02","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-02\"><h2>CP09-02</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">If a gallon of milk costs \\$3 now and the price is increasing 10% per year, how long before milk costs \\$10 a gallon? Note that guess and check will be required to solve the equation after it is written.</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0171","original_source":"cpm-CP09-03","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-03\"><h2>CP09-03</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">Dinner at your grandfather's favorite restaurant now costs \\$25.25 and has been increasing steadily at 4% per year. How much did it cost 35 years ago when he was courting your grandmother?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0172","original_source":"cpm-CP09-04","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-04\"><h2>CP09-04</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">The number of bacteria present in a colony is 180 at 12 noon and the bacteria grows at a rate of 22% per hour. How many will be present at 8 p.m.?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0173","original_source":"cpm-CP09-05","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-05\"><h2>CP09-05</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A house purchased for \\$226,000 has lost 4% of its value each year for the past five years. What is it worth now?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0174","original_source":"cpm-CP09-06","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-06\"><h2>CP09-06</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A 1970 comic book has appreciated 10% per year and originally sold for \\$0.35. What will it be worth in 2010?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0175","original_source":"cpm-CP09-07","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-07\"><h2>CP09-07</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A Honda Accord depreciates at 15% per year. Six years ago it was purchased for \\$21,000. What is it worth now?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0176","original_source":"cpm-CP09-08","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-08\"><h2>CP09-08</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">Inflation is at a rate of 7% per year. Today Janelle's favorite bread costs \\$3.79. What would it have cost ten years ago?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0177","original_source":"cpm-CP09-09","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-09\"><h2>CP09-09</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">Ryan's motorcycle is now worth \\$2500. It has decreased in value 12% each year since it was purchased. If he bought it four years ago, what did it cost new?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0178","original_source":"cpm-CP09-10","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-10\"><h2>CP09-10</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">The cost of a High Definition television now averages \\$1200, but the cost is decreasing about 15% per year. In how many years will the cost be under \\$500?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0179","original_source":"cpm-CP09-11","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-11\"><h2>CP09-11</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A two-bedroom house in Nashville is worth \\$110,000. If it appreciates at 2.5% per year, when will it be worth \\$200,000?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0180","original_source":"cpm-CP09-12","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-12\"><h2>CP09-12</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">Last year the principal's car was worth \\$28,000. Next year it will be worth \\$25,270. What is the annual rate of depreciation? What is the car worth now?</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0181","original_source":"cpm-CP09-13","source_lesson":"Checkpoint 9","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Build and use a contextual exponential growth/decay model for prediction or interpretation.","question_html":"<section class=\"problem\" id=\"CP09-13\"><h2>CP09-13</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 9</span> Writing Exponential Equations from Situations</div><div class=\"audit\">Audit note: Students model exponential growth or decay from a context, identify the starting value and multiplier, and answer the question using the model.</div>\n<p class=\"directions\">Write an exponential equation or expression to represent the situation, then answer the question.</p>\n<div class=\"prompt\">A concert has been sold out for weeks, and as the date of the concert draws closer, the price of the ticket increases. The cost of a pair of tickets was \\$150 yesterday and is \\$162 today. Assuming that the cost continues to increase at this rate exponentially:<ol class=\"subparts\"><li>What is the daily rate of increase? What is the multiplier?</li><li>What will be the cost one week from now, the day before the concert?</li><li>What was the cost two weeks ago?</li></ol></div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0182","original_source":"cpm-CP10A-09","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Interpret an exponential equation by writing a possible real-world context; model meaning dominates.","question_html":"<section class=\"problem\" id=\"CP10A-09\"><h2>CP10A-09</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students interpret an exponential decay equation by writing a possible real-world context.</div>\n<p class=\"directions\">Write a possible context based on the equation.</p>\n<div class=\"prompt\">$y=32{,}500(0.85)^x$</div>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit07-0183","original_source":"cpm-CP10A-10","source_lesson":"Checkpoint 10A","category":"Unit 7: Exponential Functions and Modeling","section":"5","unit_section_title":"Unit 7, Section 5: Exponential Modeling","source_type":"Checkpoint","audit_status":"authoritative","notes":"Interpret an exponential equation by writing a possible real-world context; model meaning dominates.","question_html":"<section class=\"problem\" id=\"CP10A-10\"><h2>CP10A-10</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 10A</span> The Exponential Web</div><div class=\"audit\">Audit note: Students interpret an exponential growth equation by writing a possible real-world context.</div>\n<p class=\"directions\">Write a possible context based on the equation.</p>\n<div class=\"prompt\">$f(x)=2.75(1.025)^x$</div>\n<div class=\"workspace\"></div>\n</section>"}];